const IMPORT_ASSETS = [{"name":"計分規則","description":"課堂積分機制：出席、互動、作業、獎勵，附hover互動動畫","type":"svg","tags":["計分","規則","教學"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes slideUp { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes slideRight { from { opacity: 0; transform: translateX(-20px); } to { opacity: 1; transform: translateX(0); } }\n  @keyframes drawLine { from { stroke-dashoffset: 400; } to { stroke-dashoffset: 0; } }\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes pulse { 0%,100% { transform: scale(1); } 50% { transform: scale(1.12); } }\n\n  .title { animation: slideUp 0.6s ease-out both; }\n  .accent-line { animation: drawLine 0.8s ease-out 0.2s both; stroke-dasharray: 400; }\n  .row-1 { animation: slideRight 0.5s ease-out 0.4s both; }\n  .row-2 { animation: slideRight 0.5s ease-out 0.6s both; }\n  .row-3 { animation: slideRight 0.5s ease-out 0.8s both; }\n  .row-4 { animation: slideRight 0.5s ease-out 1.0s both; }\n\n  .dot { cursor: pointer; transition: filter 0.25s, r 0.25s; }\n  .dot:hover { filter: drop-shadow(0 0 10px currentColor) brightness(1.3); r: 18; }\n\n  .rule-group { cursor: pointer; }\n  .rule-group .card-bg { transition: opacity 0.25s, filter 0.25s; }\n  .rule-group:hover .card-bg { opacity: 0.8 !important; filter: drop-shadow(0 2px 8px rgba(0,0,0,0.06)); }\n  .rule-group .score-badge { transition: transform 0.2s, filter 0.2s; }\n  .rule-group:hover .score-badge { filter: brightness(1.15) drop-shadow(0 2px 8px rgba(99,102,241,0.3)); }\n  .rule-group .rule-label { transition: fill 0.2s; }\n  .rule-group:hover .rule-label { fill: #0f172a; }\n  .rule-group .sub-label { transition: fill 0.2s; }\n  .rule-group:hover .sub-label { fill: #64748b; }\n\n  .reward-glow { animation: pulse 2.5s ease-in-out 1.5s infinite; transform-origin: 120px 394px; }\n  .footer { animation: fadeIn 0.5s ease-out 1.4s both; }\n</style>\n\n<!-- 背景 -->\n<rect width=\"960\" height=\"540\" fill=\"#ffffff\" rx=\"16\"/>\n\n<!-- 左側裝飾線 -->\n<line class=\"accent-line\" x1=\"80\" y1=\"95\" x2=\"80\" y2=\"445\" stroke=\"#6366f1\" stroke-width=\"4\" stroke-linecap=\"round\"/>\n\n<!-- 標題 -->\n<text class=\"title\" x=\"100\" y=\"72\" font-size=\"32\" font-weight=\"800\" fill=\"#1e293b\">計分規則</text>\n<text class=\"title\" x=\"880\" y=\"72\" text-anchor=\"end\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\" style=\"animation-delay:0.3s;\">即時更新於排行榜</text>\n\n<!-- Row 1: 出席簽到 -->\n<g class=\"row-1 rule-group\">\n  <rect class=\"card-bg\" x=\"90\" y=\"96\" width=\"780\" height=\"72\" rx=\"12\" fill=\"#f1f5f9\" opacity=\"0\"/>\n  <circle class=\"dot\" cx=\"120\" cy=\"132\" r=\"14\" fill=\"#6366f1\">\n    <title>上線簽到即得 1 分</title>\n  </circle>\n  <text class=\"rule-label\" x=\"150\" y=\"126\" font-size=\"22\" font-weight=\"700\" fill=\"#334155\">出席簽到</text>\n  <text class=\"sub-label\" x=\"150\" y=\"150\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">加入課程即自動獲得</text>\n  <g class=\"score-badge\">\n    <rect x=\"710\" y=\"113\" width=\"72\" height=\"38\" rx=\"8\" fill=\"rgba(99,102,241,0.08)\" stroke=\"#6366f1\" stroke-width=\"1.5\"/>\n    <text x=\"746\" y=\"138\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"800\" fill=\"#6366f1\">1 分</text>\n  </g>\n</g>\n\n<!-- Row 2: 參與互動 -->\n<g class=\"row-2 rule-group\">\n  <rect class=\"card-bg\" x=\"90\" y=\"180\" width=\"780\" height=\"72\" rx=\"12\" fill=\"#f1f5f9\" opacity=\"0\"/>\n  <circle class=\"dot\" cx=\"120\" cy=\"216\" r=\"14\" fill=\"#a855f7\">\n    <title>投票、問答、搶答最高 10 分</title>\n  </circle>\n  <text class=\"rule-label\" x=\"150\" y=\"210\" font-size=\"22\" font-weight=\"700\" fill=\"#334155\">參與互動</text>\n  <text class=\"sub-label\" x=\"150\" y=\"234\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">投票 ∙ 問答 ∙ 搶答 ∙ 配對</text>\n  <g class=\"score-badge\">\n    <rect x=\"670\" y=\"197\" width=\"112\" height=\"38\" rx=\"8\" fill=\"rgba(168,85,247,0.08)\" stroke=\"#a855f7\" stroke-width=\"1.5\"/>\n    <text x=\"726\" y=\"222\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"800\" fill=\"#a855f7\">1–10 分</text>\n  </g>\n</g>\n\n<!-- Row 3: 作業繳交 -->\n<g class=\"row-3 rule-group\">\n  <rect class=\"card-bg\" x=\"90\" y=\"264\" width=\"780\" height=\"72\" rx=\"12\" fill=\"#f1f5f9\" opacity=\"0\"/>\n  <circle class=\"dot\" cx=\"120\" cy=\"300\" r=\"14\" fill=\"#22c55e\">\n    <title>依作業設定，最高 10 分</title>\n  </circle>\n  <text class=\"rule-label\" x=\"150\" y=\"294\" font-size=\"22\" font-weight=\"700\" fill=\"#334155\">作業繳交</text>\n  <text class=\"sub-label\" x=\"150\" y=\"318\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">完成課堂作業並提交</text>\n  <g class=\"score-badge\">\n    <rect x=\"670\" y=\"281\" width=\"112\" height=\"38\" rx=\"8\" fill=\"rgba(34,197,94,0.08)\" stroke=\"#22c55e\" stroke-width=\"1.5\"/>\n    <text x=\"726\" y=\"306\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"800\" fill=\"#16a34a\">1–10 分</text>\n  </g>\n</g>\n\n<!-- Row 4: 冠軍獎勵 -->\n<g class=\"row-4 rule-group\">\n  <rect class=\"card-bg\" x=\"90\" y=\"348\" width=\"780\" height=\"88\" rx=\"12\" fill=\"#f1f5f9\" opacity=\"0\"/>\n  <circle class=\"dot reward-glow\" cx=\"120\" cy=\"390\" r=\"14\" fill=\"#f59e0b\">\n    <title>排行榜第一名獲得特別獎品！</title>\n  </circle>\n  <text class=\"rule-label\" x=\"150\" y=\"380\" font-size=\"22\" font-weight=\"700\" fill=\"#334155\">🏆 冠軍獎勵</text>\n  <text class=\"sub-label\" x=\"150\" y=\"412\" font-size=\"17\" font-weight=\"600\" fill=\"#b45309\">獲得「數位簡報室線上課程」一個</text>\n  <g class=\"score-badge\">\n    <rect x=\"670\" y=\"370\" width=\"112\" height=\"38\" rx=\"8\" fill=\"rgba(245,158,11,0.1)\" stroke=\"#f59e0b\" stroke-width=\"1.5\"/>\n    <text x=\"726\" y=\"395\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"800\" fill=\"#f59e0b\">🎁 獎品</text>\n  </g>\n</g>\n\n<!-- 底部 -->\n<g class=\"footer\">\n  <line x1=\"200\" y1=\"490\" x2=\"760\" y2=\"490\" stroke=\"#e2e8f0\" stroke-width=\"1\"/>\n  <text x=\"480\" y=\"515\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">積極參與就能拿高分 — 把握每一次互動機會！</text>\n</g>\n</svg>\n"},{"name":"服務項目總覽","description":"三欄深色卡片：AI專家派遣、AI內訓、Threads代操","type":"svg","tags":["服務","介紹","行銷"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes scaleIn { from { transform: scale(0.92); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n\n  .bg { animation: fadeIn 0.4s ease-out both; }\n  .main-title { animation: slideUp 0.5s ease-out 0.2s both; }\n  .card-1 { animation: scaleIn 0.5s ease-out 0.4s both; transform-origin: 178px 300px; }\n  .card-2 { animation: scaleIn 0.5s ease-out 0.6s both; transform-origin: 480px 300px; }\n  .card-3 { animation: scaleIn 0.5s ease-out 0.8s both; transform-origin: 782px 300px; }\n\n  .card-rect { cursor: pointer; transition: filter 0.25s, transform 0.25s; }\n  .card-group:hover .card-rect { filter: brightness(1.15) drop-shadow(0 4px 16px rgba(0,0,0,0.25)); }\n  .card-group:hover .card-icon { opacity: 1; }\n  .card-icon { opacity: 0.7; transition: opacity 0.2s; }\n\n  .tag { cursor: pointer; transition: opacity 0.2s; }\n  .tag:hover { opacity: 0.8; }\n</style>\n\n<!-- 背景 -->\n<rect class=\"bg\" width=\"960\" height=\"540\" rx=\"16\" fill=\"#f8fafc\"/>\n\n<!-- 頂部裝飾線 -->\n<rect class=\"bg\" x=\"0\" y=\"0\" width=\"960\" height=\"6\" rx=\"3\" fill=\"url(#svc-topbar)\"/>\n<defs>\n  <linearGradient id=\"svc-topbar\" x1=\"0\" y1=\"0\" x2=\"960\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#6366f1\"/>\n    <stop offset=\"50%\" stop-color=\"#a855f7\"/>\n    <stop offset=\"100%\" stop-color=\"#06b6d4\"/>\n  </linearGradient>\n  <linearGradient id=\"svc-cardbg\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n    <stop offset=\"0%\" stop-color=\"#1e293b\"/>\n    <stop offset=\"100%\" stop-color=\"#0f172a\"/>\n  </linearGradient>\n</defs>\n\n<!-- 主標題 -->\n<text class=\"main-title\" x=\"480\" y=\"56\" text-anchor=\"middle\" font-size=\"16\" font-weight=\"600\" fill=\"#6366f1\" letter-spacing=\"4\">OUR SERVICES</text>\n<text class=\"main-title\" x=\"480\" y=\"88\" text-anchor=\"middle\" font-size=\"28\" font-weight=\"800\" fill=\"#1e293b\" style=\"animation-delay:0.3s;\">我們的服務</text>\n\n<!-- ═══ Card 1: AI 專家派遣 ═══ -->\n<g class=\"card-1 card-group\">\n  <rect class=\"card-rect\" x=\"40\" y=\"120\" width=\"275\" height=\"380\" rx=\"16\" fill=\"url(#svc-cardbg)\"/>\n  \n  <!-- 頂部標籤 -->\n  <rect class=\"tag\" x=\"55\" y=\"135\" width=\"80\" height=\"24\" rx=\"12\" fill=\"rgba(99,102,241,0.25)\"/>\n  <text x=\"95\" y=\"152\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#a5b4fc\">企業導入</text>\n  \n  <!-- Icon -->\n  <text class=\"card-icon\" x=\"55\" y=\"200\" font-size=\"36\">🧑‍💻</text>\n  \n  <!-- 標題 -->\n  <text x=\"55\" y=\"240\" font-size=\"20\" font-weight=\"800\" fill=\"#ffffff\">AI 專家派遣</text>\n  <text x=\"55\" y=\"262\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">AI 專家 ＋ PM 進駐辦公室</text>\n\n  <!-- 分隔線 -->\n  <line x1=\"55\" y1=\"280\" x2=\"295\" y2=\"280\" stroke=\"#334155\" stroke-width=\"1\"/>\n  \n  <!-- 項目 -->\n  <circle cx=\"65\" cy=\"308\" r=\"4\" fill=\"#6366f1\"/>\n  <text x=\"80\" y=\"313\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">流程再造與 AI 化</text>\n  \n  <circle cx=\"65\" cy=\"342\" r=\"4\" fill=\"#6366f1\"/>\n  <text x=\"80\" y=\"347\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">老系統智慧升級</text>\n  \n  <circle cx=\"65\" cy=\"376\" r=\"4\" fill=\"#6366f1\"/>\n  <text x=\"80\" y=\"381\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">跨系統數據串聯</text>\n\n  <!-- 底部裝飾 -->\n  <rect x=\"40\" y=\"470\" width=\"275\" height=\"30\" rx=\"0\" ry=\"0\" fill=\"rgba(99,102,241,0.12)\"/>\n  <rect x=\"40\" y=\"484\" width=\"275\" height=\"16\" rx=\"0\" ry=\"16\" fill=\"rgba(99,102,241,0.12)\"/>\n  <text x=\"178\" y=\"490\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#818cf8\">由我們的團隊進駐</text>\n</g>\n\n<!-- ═══ Card 2: AI 培訓 ═══ -->\n<g class=\"card-2 card-group\">\n  <rect class=\"card-rect\" x=\"342\" y=\"120\" width=\"275\" height=\"380\" rx=\"16\" fill=\"url(#svc-cardbg)\"/>\n  \n  <rect class=\"tag\" x=\"357\" y=\"135\" width=\"80\" height=\"24\" rx=\"12\" fill=\"rgba(168,85,247,0.25)\"/>\n  <text x=\"397\" y=\"152\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#c4b5fd\">教育培訓</text>\n  \n  <text class=\"card-icon\" x=\"357\" y=\"200\" font-size=\"36\">🎓</text>\n  \n  <text x=\"357\" y=\"240\" font-size=\"20\" font-weight=\"800\" fill=\"#ffffff\">AI 內訓 / 培育</text>\n  <text x=\"357\" y=\"262\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">帶企業與個人深化 AI 應用</text>\n  \n  <line x1=\"357\" y1=\"280\" x2=\"597\" y2=\"280\" stroke=\"#334155\" stroke-width=\"1\"/>\n  \n  <circle cx=\"367\" cy=\"308\" r=\"4\" fill=\"#a855f7\"/>\n  <text x=\"382\" y=\"313\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">企業內部 AI 培訓</text>\n  \n  <circle cx=\"367\" cy=\"342\" r=\"4\" fill=\"#a855f7\"/>\n  <text x=\"382\" y=\"347\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">一對一個人教練</text>\n  \n  <circle cx=\"367\" cy=\"376\" r=\"4\" fill=\"#a855f7\"/>\n  <text x=\"382\" y=\"381\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">實戰工作坊設計</text>\n\n  <rect x=\"342\" y=\"470\" width=\"275\" height=\"30\" rx=\"0\" ry=\"0\" fill=\"rgba(168,85,247,0.12)\"/>\n  <rect x=\"342\" y=\"484\" width=\"275\" height=\"16\" rx=\"0\" ry=\"16\" fill=\"rgba(168,85,247,0.12)\"/>\n  <text x=\"480\" y=\"490\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#a78bfa\">量身定制學習路徑</text>\n</g>\n\n<!-- ═══ Card 3: Threads 代操 ═══ -->\n<g class=\"card-3 card-group\">\n  <rect class=\"card-rect\" x=\"644\" y=\"120\" width=\"275\" height=\"380\" rx=\"16\" fill=\"url(#svc-cardbg)\"/>\n  \n  <rect class=\"tag\" x=\"659\" y=\"135\" width=\"80\" height=\"24\" rx=\"12\" fill=\"rgba(6,182,212,0.25)\"/>\n  <text x=\"699\" y=\"152\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#67e8f9\">社群經營</text>\n  \n  <text class=\"card-icon\" x=\"659\" y=\"200\" font-size=\"36\">📱</text>\n  \n  <text x=\"659\" y=\"240\" font-size=\"20\" font-weight=\"800\" fill=\"#ffffff\">Threads 代操</text>\n  <text x=\"659\" y=\"262\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">社群帶營運 ＋ 數據驅動</text>\n  \n  <line x1=\"659\" y1=\"280\" x2=\"899\" y2=\"280\" stroke=\"#334155\" stroke-width=\"1\"/>\n  \n  <circle cx=\"669\" cy=\"308\" r=\"4\" fill=\"#06b6d4\"/>\n  <text x=\"684\" y=\"313\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">Threads 帳號代操</text>\n  \n  <circle cx=\"669\" cy=\"342\" r=\"4\" fill=\"#06b6d4\"/>\n  <text x=\"684\" y=\"347\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">SEO 內容策略輔助</text>\n  \n  <circle cx=\"669\" cy=\"376\" r=\"4\" fill=\"#06b6d4\"/>\n  <text x=\"684\" y=\"381\" font-size=\"15\" font-weight=\"600\" fill=\"#e2e8f0\">數據整合與成效控管</text>\n\n  <rect x=\"644\" y=\"470\" width=\"275\" height=\"30\" rx=\"0\" ry=\"0\" fill=\"rgba(6,182,212,0.12)\"/>\n  <rect x=\"644\" y=\"484\" width=\"275\" height=\"16\" rx=\"0\" ry=\"16\" fill=\"rgba(6,182,212,0.12)\"/>\n  <text x=\"782\" y=\"490\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#22d3ee\">用數據說話的社群</text>\n</g>\n\n<!-- 底部 -->\n<text x=\"480\" y=\"528\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\" style=\"animation: fadeIn 0.5s ease-out 1.2s both;\">\n  從策略到落地，AI 轉型全方位支援\n</text>\n</svg>\n"},{"name":"講師簡介 — 樊松蒲 Dennis","description":"講師個人檔案：20+合作單位、底部統計數據","type":"svg","tags":["講師","簡介","個人"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes slideUp { from { opacity: 0; transform: translateY(18px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes slideRight { from { opacity: 0; transform: translateX(-15px); } to { opacity: 1; transform: translateX(0); } }\n  @keyframes scaleIn { from { transform: scale(0); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n  @keyframes drawCircle { from { stroke-dashoffset: 500; } to { stroke-dashoffset: 0; } }\n\n  .bg { animation: fadeIn 0.3s ease-out both; }\n  .avatar-ring { animation: drawCircle 1s ease-out 0.3s both; stroke-dasharray: 500; }\n  .avatar-fill { animation: scaleIn 0.5s ease-out 0.5s both; transform-origin: 120px 160px; }\n  .name { animation: slideUp 0.5s ease-out 0.3s both; }\n  .title-text { animation: slideUp 0.5s ease-out 0.5s both; }\n  .divider { animation: fadeIn 0.4s ease-out 0.6s both; }\n  .platform { animation: slideRight 0.4s ease-out 0.7s both; }\n  .client-grid { animation: fadeIn 0.5s ease-out 0.8s both; }\n  .photo-area { animation: slideUp 0.4s ease-out 1.0s both; }\n\n  .client-tag { cursor: pointer; transition: opacity 0.2s, transform 0.15s; }\n  .client-tag:hover { opacity: 1 !important; }\n  .client-tag:hover rect { filter: brightness(0.95); }\n  .client-tag:hover text { fill: #1e293b !important; }\n  .platform-badge { cursor: pointer; transition: filter 0.2s; }\n  .platform-badge:hover { filter: brightness(1.1) drop-shadow(0 2px 6px rgba(0,0,0,0.12)); }\n  .photo-card { cursor: pointer; transition: filter 0.2s, transform 0.15s; }\n  .photo-card:hover { filter: brightness(1.05) drop-shadow(0 3px 10px rgba(0,0,0,0.15)); }\n</style>\n\n<!-- 背景 -->\n<rect class=\"bg\" width=\"960\" height=\"540\" rx=\"16\" fill=\"#ffffff\"/>\n\n<!-- 左側深色區塊 -->\n<rect class=\"bg\" x=\"0\" y=\"0\" width=\"240\" height=\"540\" rx=\"16\" fill=\"#0f172a\"/>\n<rect class=\"bg\" x=\"16\" y=\"0\" width=\"224\" height=\"540\" fill=\"#0f172a\"/>\n\n<!-- 頭像區域 -->\n<circle class=\"avatar-ring\" cx=\"120\" cy=\"160\" r=\"72\" fill=\"none\" stroke=\"#6366f1\" stroke-width=\"3\"/>\n<circle class=\"avatar-fill\" cx=\"120\" cy=\"160\" r=\"68\" fill=\"#1e293b\"/>\n<text x=\"120\" y=\"150\" text-anchor=\"middle\" font-size=\"42\" fill=\"#e2e8f0\" style=\"animation: scaleIn 0.5s ease-out 0.6s both;\">🧑‍💼</text>\n<text x=\"120\" y=\"185\" text-anchor=\"middle\" font-size=\"11\" fill=\"#64748b\" style=\"animation: fadeIn 0.4s ease-out 0.7s both;\">SPEAKER</text>\n\n<!-- 左側資訊 -->\n<text class=\"name\" x=\"120\" y=\"265\" text-anchor=\"middle\" font-size=\"26\" font-weight=\"800\" fill=\"#ffffff\">樊松蒲</text>\n<text class=\"name\" x=\"120\" y=\"292\" text-anchor=\"middle\" font-size=\"16\" font-weight=\"600\" fill=\"#a5b4fc\" style=\"animation-delay:0.4s;\">Dennis</text>\n\n<line class=\"divider\" x1=\"50\" y1=\"310\" x2=\"190\" y2=\"310\" stroke=\"#334155\" stroke-width=\"1\"/>\n\n<text class=\"title-text\" x=\"120\" y=\"340\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"600\" fill=\"#94a3b8\">數位簡報室 創辦人</text>\n<text class=\"title-text\" x=\"120\" y=\"365\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"600\" fill=\"#94a3b8\" style=\"animation-delay:0.55s;\">AI 內訓講師</text>\n\n<!-- 左側活動圖示 -->\n<g class=\"photo-area\">\n  <rect x=\"30\" y=\"395\" width=\"85\" height=\"60\" rx=\"8\" fill=\"#1e293b\" stroke=\"#334155\" stroke-width=\"1\"/>\n  <text x=\"72\" y=\"432\" text-anchor=\"middle\" font-size=\"24\">🎤</text>\n  <rect x=\"125\" y=\"395\" width=\"85\" height=\"60\" rx=\"8\" fill=\"#1e293b\" stroke=\"#334155\" stroke-width=\"1\"/>\n  <text x=\"167\" y=\"432\" text-anchor=\"middle\" font-size=\"24\">👥</text>\n  <text x=\"120\" y=\"485\" text-anchor=\"middle\" font-size=\"11\" fill=\"#64748b\">企業培訓 ∙ 實戰工作坊</text>\n</g>\n\n<!-- ═══ 右側內容 ═══ -->\n\n<!-- 合作平台 -->\n<g class=\"platform\">\n  <text x=\"280\" y=\"50\" font-size=\"12\" font-weight=\"600\" fill=\"#94a3b8\" letter-spacing=\"2\">合作平台</text>\n  \n  <g class=\"platform-badge\">\n    <rect x=\"780\" y=\"28\" width=\"110\" height=\"32\" rx=\"6\" fill=\"#f8fafc\" stroke=\"#e2e8f0\" stroke-width=\"1\"/>\n    <text x=\"835\" y=\"50\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#1e293b\">hahow</text>\n  </g>\n  <g class=\"platform-badge\">\n    <rect x=\"780\" y=\"68\" width=\"110\" height=\"32\" rx=\"6\" fill=\"#f8fafc\" stroke=\"#e2e8f0\" stroke-width=\"1\"/>\n    <text x=\"835\" y=\"90\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"700\" fill=\"#1e293b\">PressPlay</text>\n  </g>\n  <g class=\"platform-badge\">\n    <rect x=\"780\" y=\"108\" width=\"110\" height=\"32\" rx=\"6\" fill=\"#f8fafc\" stroke=\"#e2e8f0\" stroke-width=\"1\"/>\n    <text x=\"835\" y=\"130\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"700\" fill=\"#1e293b\">104 人力</text>\n  </g>\n</g>\n\n<!-- 授課 / 合作單位標題 -->\n<text class=\"platform\" x=\"280\" y=\"90\" font-size=\"22\" font-weight=\"800\" fill=\"#1e293b\">授課與合作單位</text>\n<line class=\"divider\" x1=\"280\" y1=\"102\" x2=\"740\" y2=\"102\" stroke=\"#e2e8f0\" stroke-width=\"1\"/>\n\n<!-- 客戶清單 Grid -->\n<g class=\"client-grid\">\n  <!-- Row 1 -->\n  <g class=\"client-tag\"><rect x=\"280\" y=\"118\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"350\" y=\"140\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">臺灣科技大學</text></g>\n  <g class=\"client-tag\"><rect x=\"430\" y=\"118\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"500\" y=\"140\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">Volvo</text></g>\n  <g class=\"client-tag\"><rect x=\"580\" y=\"118\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"650\" y=\"140\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">光彩旅遊</text></g>\n\n  <!-- Row 2 -->\n  <g class=\"client-tag\"><rect x=\"280\" y=\"160\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"350\" y=\"182\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">萬能科技大學</text></g>\n  <g class=\"client-tag\"><rect x=\"430\" y=\"160\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"500\" y=\"182\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">新娘物語</text></g>\n  <g class=\"client-tag\"><rect x=\"580\" y=\"160\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"650\" y=\"182\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">聖研保養品</text></g>\n\n  <!-- Row 3 -->\n  <g class=\"client-tag\"><rect x=\"280\" y=\"202\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"350\" y=\"224\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">精英電腦</text></g>\n  <g class=\"client-tag\"><rect x=\"430\" y=\"202\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"500\" y=\"224\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">寵物公園</text></g>\n  <g class=\"client-tag\"><rect x=\"580\" y=\"202\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"650\" y=\"224\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">森料理</text></g>\n\n  <!-- Row 4 -->\n  <g class=\"client-tag\"><rect x=\"280\" y=\"244\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"350\" y=\"266\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">中國台灣旅行社</text></g>\n  <g class=\"client-tag\"><rect x=\"430\" y=\"244\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"500\" y=\"266\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">台灣導遊協會</text></g>\n  <g class=\"client-tag\"><rect x=\"580\" y=\"244\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"650\" y=\"266\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">這味泰泰</text></g>\n\n  <!-- Row 5 -->\n  <g class=\"client-tag\"><rect x=\"280\" y=\"286\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"350\" y=\"308\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">元本旅遊</text></g>\n  <g class=\"client-tag\"><rect x=\"430\" y=\"286\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"500\" y=\"308\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">智谷網路</text></g>\n  <g class=\"client-tag\"><rect x=\"580\" y=\"286\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"650\" y=\"308\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">PChome</text></g>\n\n  <!-- Row 6 -->\n  <g class=\"client-tag\"><rect x=\"280\" y=\"328\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"350\" y=\"350\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">邁思旅行社</text></g>\n  <g class=\"client-tag\"><rect x=\"430\" y=\"328\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"500\" y=\"350\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">Welly SEO</text></g>\n  <g class=\"client-tag\"><rect x=\"580\" y=\"328\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"650\" y=\"350\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">燕府旅遊</text></g>\n\n  <!-- Row 7 -->\n  <g class=\"client-tag\"><rect x=\"280\" y=\"370\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"350\" y=\"392\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">時代基金會</text></g>\n  <g class=\"client-tag\"><rect x=\"430\" y=\"370\" width=\"140\" height=\"34\" rx=\"8\" fill=\"#f1f5f9\"/><text x=\"500\" y=\"392\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#334155\">沃恩長照機構</text></g>\n</g>\n\n<!-- 底部統計 -->\n<g style=\"animation: slideUp 0.4s ease-out 1.2s both;\">\n  <rect x=\"280\" y=\"425\" width=\"140\" height=\"52\" rx=\"10\" fill=\"rgba(99,102,241,0.06)\" stroke=\"#c7d2fe\" stroke-width=\"1\"/>\n  <text x=\"350\" y=\"448\" text-anchor=\"middle\" font-size=\"22\" font-weight=\"800\" fill=\"#6366f1\">20+</text>\n  <text x=\"350\" y=\"468\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#94a3b8\">合作單位</text>\n\n  <rect x=\"440\" y=\"425\" width=\"140\" height=\"52\" rx=\"10\" fill=\"rgba(168,85,247,0.06)\" stroke=\"#ddd6fe\" stroke-width=\"1\"/>\n  <text x=\"510\" y=\"448\" text-anchor=\"middle\" font-size=\"22\" font-weight=\"800\" fill=\"#a855f7\">100+</text>\n  <text x=\"510\" y=\"468\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#94a3b8\">場次授課</text>\n\n  <rect x=\"600\" y=\"425\" width=\"140\" height=\"52\" rx=\"10\" fill=\"rgba(34,197,94,0.06)\" stroke=\"#bbf7d0\" stroke-width=\"1\"/>\n  <text x=\"670\" y=\"448\" text-anchor=\"middle\" font-size=\"22\" font-weight=\"800\" fill=\"#22c55e\">3000+</text>\n  <text x=\"670\" y=\"468\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#94a3b8\">學員人數</text>\n</g>\n\n<!-- 底部裝飾 -->\n<rect x=\"280\" y=\"500\" width=\"610\" height=\"4\" rx=\"2\" fill=\"url(#gradBottom)\" style=\"animation: fadeIn 0.4s ease-out 1.4s both;\"/>\n<defs>\n  <linearGradient id=\"gradBottom\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#6366f1\"/>\n    <stop offset=\"50%\" stop-color=\"#a855f7\"/>\n    <stop offset=\"100%\" stop-color=\"#22c55e\"/>\n  </linearGradient>\n</defs>\n\n<text x=\"585\" y=\"525\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"500\" fill=\"#cbd5e1\" style=\"animation: fadeIn 0.4s ease-out 1.5s both;\">從簡報設計到 AI 落地，陪你的團隊一起進化</text>\n</svg>\n"},{"name":"AI 三大使用原則","description":"不盲信、不洩密、要給情境，附hover互動與進場動畫","type":"svg","tags":["AI","原則","教學"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes slideUp { from { opacity: 0; transform: translateY(18px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes slideRight { from { opacity: 0; transform: translateX(-20px); } to { opacity: 1; transform: translateX(0); } }\n  @keyframes drawLine { from { stroke-dashoffset: 200; } to { stroke-dashoffset: 0; } }\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes scaleIn { from { transform: scale(0); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n  @keyframes countPulse { 0%,100% { transform: scale(1); } 50% { transform: scale(1.2); } }\n\n  .title { animation: slideUp 0.6s ease-out both; }\n  .title-line { animation: drawLine 0.6s ease-out 0.3s both; stroke-dasharray: 200; }\n  .rule-1 { animation: slideRight 0.5s ease-out 0.5s both; }\n  .rule-2 { animation: slideRight 0.5s ease-out 0.7s both; }\n  .rule-3 { animation: slideRight 0.5s ease-out 0.9s both; }\n\n  .num { animation: scaleIn 0.4s ease-out both; }\n  .num-1 { animation-delay: 0.5s; transform-origin: 88px 195px; }\n  .num-2 { animation-delay: 0.7s; transform-origin: 88px 310px; }\n  .num-3 { animation-delay: 0.9s; transform-origin: 88px 425px; }\n\n  .rule-card { cursor: pointer; }\n  .rule-card .card-bg { transition: opacity 0.25s, filter 0.25s; opacity: 0; }\n  .rule-card:hover .card-bg { opacity: 1; filter: drop-shadow(0 2px 12px rgba(0,0,0,0.06)); }\n  .rule-card:hover .keyword { fill: #0f172a; }\n  .rule-card:hover .desc { fill: #334155; }\n  .rule-card .keyword { transition: fill 0.2s; }\n  .rule-card .desc { transition: fill 0.2s; }\n\n  .dot { cursor: pointer; transition: r 0.2s, filter 0.2s; }\n  .dot:hover { r: 24; filter: drop-shadow(0 0 10px rgba(22,163,74,0.4)); }\n\n  .icon-badge { transition: transform 0.2s; }\n  .rule-card:hover .icon-badge { transform: scale(1.15); }\n\n  .footer { animation: fadeIn 0.5s ease-out 1.2s both; }\n</style>\n\n<!-- 背景 -->\n<rect width=\"960\" height=\"540\" fill=\"#ffffff\" rx=\"16\"/>\n\n<!-- 頂部漸層裝飾 -->\n<rect x=\"0\" y=\"0\" width=\"960\" height=\"5\" rx=\"2.5\" fill=\"url(#topGrad)\"/>\n<defs>\n  <linearGradient id=\"topGrad\" x1=\"0\" y1=\"0\" x2=\"960\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#16a34a\"/>\n    <stop offset=\"50%\" stop-color=\"#22c55e\"/>\n    <stop offset=\"100%\" stop-color=\"#4ade80\"/>\n  </linearGradient>\n</defs>\n\n<!-- 標題 -->\n<text class=\"title\" x=\"80\" y=\"80\" font-size=\"30\" font-weight=\"800\" fill=\"#1e293b\">AI 的三大使用原則</text>\n<line class=\"title-line\" x1=\"80\" y1=\"95\" x2=\"280\" y2=\"95\" stroke=\"#16a34a\" stroke-width=\"4\" stroke-linecap=\"round\"/>\n<text class=\"title\" x=\"880\" y=\"80\" text-anchor=\"end\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\" style=\"animation-delay:0.4s;\">使用 AI 前的必讀守則</text>\n\n<!-- ═══ Rule 1: 不盲信 ═══ -->\n<g class=\"rule-1 rule-card\">\n  <rect class=\"card-bg\" x=\"60\" y=\"125\" width=\"840\" height=\"100\" rx=\"14\" fill=\"#f0fdf4\"/>\n  \n  <!-- 數字圓 -->\n  <circle class=\"dot num num-1\" cx=\"88\" cy=\"175\" r=\"20\" fill=\"#16a34a\"/>\n  <text x=\"88\" y=\"181\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"800\" fill=\"#ffffff\">1</text>\n  \n  <!-- 關鍵字 -->\n  <text class=\"keyword\" x=\"125\" y=\"162\" font-size=\"22\" font-weight=\"800\" fill=\"#16a34a\">不盲信</text>\n  \n  <!-- 箭頭 -->\n  <text x=\"230\" y=\"162\" font-size=\"16\" fill=\"#94a3b8\">→</text>\n  \n  <!-- 說明 -->\n  <text class=\"desc\" x=\"260\" y=\"162\" font-size=\"17\" font-weight=\"500\" fill=\"#475569\">AI 會幻想（Hallucination）</text>\n  <text class=\"desc\" x=\"125\" y=\"192\" font-size=\"15\" font-weight=\"500\" fill=\"#64748b\">關鍵數據一定要交叉驗證，不能照單全收</text>\n\n  <!-- 右側圖示 -->\n  <g class=\"icon-badge\" style=\"transform-origin: 850px 175px;\">\n    <rect x=\"820\" y=\"155\" width=\"42\" height=\"42\" rx=\"10\" fill=\"rgba(22,163,74,0.08)\"/>\n    <text x=\"841\" y=\"183\" text-anchor=\"middle\" font-size=\"22\">🔍</text>\n  </g>\n</g>\n\n<!-- ═══ Rule 2: 不洩密 ═══ -->\n<g class=\"rule-2 rule-card\">\n  <rect class=\"card-bg\" x=\"60\" y=\"240\" width=\"840\" height=\"100\" rx=\"14\" fill=\"#f0fdf4\"/>\n  \n  <circle class=\"dot num num-2\" cx=\"88\" cy=\"290\" r=\"20\" fill=\"#16a34a\"/>\n  <text x=\"88\" y=\"296\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"800\" fill=\"#ffffff\">2</text>\n  \n  <text class=\"keyword\" x=\"125\" y=\"277\" font-size=\"22\" font-weight=\"800\" fill=\"#16a34a\">不洩密</text>\n  <text x=\"230\" y=\"277\" font-size=\"16\" fill=\"#94a3b8\">→</text>\n  <text class=\"desc\" x=\"260\" y=\"277\" font-size=\"17\" font-weight=\"500\" fill=\"#475569\">不要把客戶機密資料、個資直接貼給公開 AI</text>\n  <text class=\"desc\" x=\"125\" y=\"307\" font-size=\"15\" font-weight=\"500\" fill=\"#64748b\">機密文件請使用企業版或本地部署方案</text>\n\n  <g class=\"icon-badge\" style=\"transform-origin: 850px 290px;\">\n    <rect x=\"820\" y=\"270\" width=\"42\" height=\"42\" rx=\"10\" fill=\"rgba(22,163,74,0.08)\"/>\n    <text x=\"841\" y=\"298\" text-anchor=\"middle\" font-size=\"22\">🔒</text>\n  </g>\n</g>\n\n<!-- ═══ Rule 3: 要給情境 ═══ -->\n<g class=\"rule-3 rule-card\">\n  <rect class=\"card-bg\" x=\"60\" y=\"355\" width=\"840\" height=\"100\" rx=\"14\" fill=\"#f0fdf4\"/>\n  \n  <circle class=\"dot num num-3\" cx=\"88\" cy=\"405\" r=\"20\" fill=\"#16a34a\"/>\n  <text x=\"88\" y=\"411\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"800\" fill=\"#ffffff\">3</text>\n  \n  <text class=\"keyword\" x=\"125\" y=\"392\" font-size=\"22\" font-weight=\"800\" fill=\"#16a34a\">要給情境</text>\n  <text x=\"260\" y=\"392\" font-size=\"16\" fill=\"#94a3b8\">→</text>\n  <text class=\"desc\" x=\"290\" y=\"392\" font-size=\"17\" font-weight=\"500\" fill=\"#475569\">AI 不是通靈，你給的背景越多，產出越精準</text>\n  <text class=\"desc\" x=\"125\" y=\"422\" font-size=\"15\" font-weight=\"500\" fill=\"#64748b\">角色、目的、受眾、格式 — 寫清楚再送出</text>\n\n  <g class=\"icon-badge\" style=\"transform-origin: 850px 405px;\">\n    <rect x=\"820\" y=\"385\" width=\"42\" height=\"42\" rx=\"10\" fill=\"rgba(22,163,74,0.08)\"/>\n    <text x=\"841\" y=\"413\" text-anchor=\"middle\" font-size=\"22\">🎯</text>\n  </g>\n</g>\n\n<!-- 底部 -->\n<g class=\"footer\">\n  <line x1=\"200\" y1=\"490\" x2=\"760\" y2=\"490\" stroke=\"#e2e8f0\" stroke-width=\"1\"/>\n  <text x=\"480\" y=\"518\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">掌握原則，讓 AI 成為你最可靠的工作夥伴</text>\n</g>\n</svg>\n"},{"name":"提示工程基本框架","description":"Role/Context/Task/Format/Constraint 五要素範例","type":"svg","tags":["AI","提示工程","Prompt","教學"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes slideUp { from { opacity: 0; transform: translateY(18px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes slideRight { from { opacity: 0; transform: translateX(-20px); } to { opacity: 1; transform: translateX(0); } }\n  @keyframes drawLine { from { stroke-dashoffset: 200; } to { stroke-dashoffset: 0; } }\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes scaleIn { from { transform: scale(0); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n\n  .title { animation: slideUp 0.6s ease-out both; }\n  .title-line { animation: drawLine 0.6s ease-out 0.3s both; stroke-dasharray: 200; }\n  .row-1 { animation: slideRight 0.5s ease-out 0.4s both; }\n  .row-2 { animation: slideRight 0.5s ease-out 0.55s both; }\n  .row-3 { animation: slideRight 0.5s ease-out 0.7s both; }\n  .row-4 { animation: slideRight 0.5s ease-out 0.85s both; }\n  .row-5 { animation: slideRight 0.5s ease-out 1.0s both; }\n\n  .dot { transition: r 0.2s, filter 0.2s; cursor: pointer; }\n  .dot:hover { r: 18; filter: drop-shadow(0 0 10px rgba(124,58,237,0.5)); }\n\n  .rule-card { cursor: pointer; }\n  .rule-card .card-bg { transition: opacity 0.25s; opacity: 0; }\n  .rule-card:hover .card-bg { opacity: 1; }\n  .rule-card:hover .kw { fill: #4c1d95; }\n  .rule-card:hover .eng { fill: #7c3aed; }\n  .rule-card:hover .example { fill: #1e293b; }\n  .rule-card .kw { transition: fill 0.2s; }\n  .rule-card .eng { transition: fill 0.2s; }\n  .rule-card .example { transition: fill 0.2s; }\n\n  .rule-card:hover .icon-box { opacity: 1; transform: scale(1.1); }\n  .icon-box { opacity: 0.6; transition: opacity 0.2s, transform 0.2s; }\n\n  .footer { animation: fadeIn 0.5s ease-out 1.3s both; }\n</style>\n\n<!-- 背景 -->\n<rect width=\"960\" height=\"540\" fill=\"#ffffff\" rx=\"16\"/>\n\n<!-- 頂部漸層 -->\n<rect x=\"0\" y=\"0\" width=\"960\" height=\"5\" rx=\"2.5\" fill=\"url(#topG)\"/>\n<defs>\n  <linearGradient id=\"topG\" x1=\"0\" y1=\"0\" x2=\"960\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#7c3aed\"/>\n    <stop offset=\"50%\" stop-color=\"#a855f7\"/>\n    <stop offset=\"100%\" stop-color=\"#c084fc\"/>\n  </linearGradient>\n</defs>\n\n<!-- 標題 -->\n<text class=\"title\" x=\"80\" y=\"72\" font-size=\"30\" font-weight=\"800\" fill=\"#1e293b\">提示工程的基本框架</text>\n<line class=\"title-line\" x1=\"80\" y1=\"87\" x2=\"310\" y2=\"87\" stroke=\"#7c3aed\" stroke-width=\"4\" stroke-linecap=\"round\"/>\n<text class=\"title\" x=\"880\" y=\"72\" text-anchor=\"end\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\" style=\"animation-delay:0.4s;\">Prompt Engineering 101</text>\n\n<!-- ═══ Row 1: 角色 Role ═══ -->\n<g class=\"row-1 rule-card\">\n  <rect class=\"card-bg\" x=\"60\" y=\"105\" width=\"840\" height=\"68\" rx=\"12\" fill=\"#f5f3ff\"/>\n  <circle class=\"dot\" cx=\"88\" cy=\"139\" r=\"13\" fill=\"#7c3aed\"><title>Role：設定 AI 的角色定位</title></circle>\n  <text class=\"kw\" x=\"115\" y=\"134\" font-size=\"20\" font-weight=\"800\" fill=\"#7c3aed\">角色</text>\n  <text class=\"eng\" x=\"175\" y=\"134\" font-size=\"14\" font-weight=\"600\" fill=\"#a78bfa\">（Role）</text>\n  <text x=\"260\" y=\"134\" font-size=\"16\" fill=\"#94a3b8\">→</text>\n  <text class=\"example\" x=\"290\" y=\"134\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">「你是一位資深的 HR 系統產品經理」</text>\n  <text class=\"example\" x=\"115\" y=\"158\" font-size=\"13\" font-weight=\"400\" fill=\"#94a3b8\">告訴 AI 它扮演什麼專家角色</text>\n  <g class=\"icon-box\" style=\"transform-origin:855px 139px;\"><text x=\"855\" y=\"147\" text-anchor=\"middle\" font-size=\"22\">🎭</text></g>\n</g>\n\n<!-- ═══ Row 2: 情境 Context ═══ -->\n<g class=\"row-2 rule-card\">\n  <rect class=\"card-bg\" x=\"60\" y=\"183\" width=\"840\" height=\"68\" rx=\"12\" fill=\"#f5f3ff\"/>\n  <circle class=\"dot\" cx=\"88\" cy=\"217\" r=\"13\" fill=\"#8b5cf6\"><title>Context：提供背景與脈絡</title></circle>\n  <text class=\"kw\" x=\"115\" y=\"212\" font-size=\"20\" font-weight=\"800\" fill=\"#7c3aed\">情境</text>\n  <text class=\"eng\" x=\"175\" y=\"212\" font-size=\"14\" font-weight=\"600\" fill=\"#a78bfa\">（Context）</text>\n  <text x=\"285\" y=\"212\" font-size=\"16\" fill=\"#94a3b8\">→</text>\n  <text class=\"example\" x=\"315\" y=\"212\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">「公司正在準備新一季的客戶提案」</text>\n  <text class=\"example\" x=\"115\" y=\"236\" font-size=\"13\" font-weight=\"400\" fill=\"#94a3b8\">說明任務的背景與使用場景</text>\n  <g class=\"icon-box\" style=\"transform-origin:855px 217px;\"><text x=\"855\" y=\"225\" text-anchor=\"middle\" font-size=\"22\">📋</text></g>\n</g>\n\n<!-- ═══ Row 3: 任務 Task ═══ -->\n<g class=\"row-3 rule-card\">\n  <rect class=\"card-bg\" x=\"60\" y=\"261\" width=\"840\" height=\"68\" rx=\"12\" fill=\"#f5f3ff\"/>\n  <circle class=\"dot\" cx=\"88\" cy=\"295\" r=\"13\" fill=\"#a855f7\"><title>Task：明確指定你要 AI 做什麼</title></circle>\n  <text class=\"kw\" x=\"115\" y=\"290\" font-size=\"20\" font-weight=\"800\" fill=\"#7c3aed\">任務</text>\n  <text class=\"eng\" x=\"175\" y=\"290\" font-size=\"14\" font-weight=\"600\" fill=\"#a78bfa\">（Task）</text>\n  <text x=\"260\" y=\"290\" font-size=\"16\" fill=\"#94a3b8\">→</text>\n  <text class=\"example\" x=\"290\" y=\"290\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">「請幫我撰寫一份產品優勢比較表」</text>\n  <text class=\"example\" x=\"115\" y=\"314\" font-size=\"13\" font-weight=\"400\" fill=\"#94a3b8\">具體說出你需要的產出是什麼</text>\n  <g class=\"icon-box\" style=\"transform-origin:855px 295px;\"><text x=\"855\" y=\"303\" text-anchor=\"middle\" font-size=\"22\">✏️</text></g>\n</g>\n\n<!-- ═══ Row 4: 格式 Format ═══ -->\n<g class=\"row-4 rule-card\">\n  <rect class=\"card-bg\" x=\"60\" y=\"339\" width=\"840\" height=\"68\" rx=\"12\" fill=\"#f5f3ff\"/>\n  <circle class=\"dot\" cx=\"88\" cy=\"373\" r=\"13\" fill=\"#c084fc\"><title>Format：指定輸出的格式</title></circle>\n  <text class=\"kw\" x=\"115\" y=\"368\" font-size=\"20\" font-weight=\"800\" fill=\"#7c3aed\">格式</text>\n  <text class=\"eng\" x=\"175\" y=\"368\" font-size=\"14\" font-weight=\"600\" fill=\"#a78bfa\">（Format）</text>\n  <text x=\"280\" y=\"368\" font-size=\"16\" fill=\"#94a3b8\">→</text>\n  <text class=\"example\" x=\"310\" y=\"368\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">「用 Markdown 表格、繁體中文」</text>\n  <text class=\"example\" x=\"115\" y=\"392\" font-size=\"13\" font-weight=\"400\" fill=\"#94a3b8\">規定產出的結構與語言</text>\n  <g class=\"icon-box\" style=\"transform-origin:855px 373px;\"><text x=\"855\" y=\"381\" text-anchor=\"middle\" font-size=\"22\">📐</text></g>\n</g>\n\n<!-- ═══ Row 5: 限制 Constraint ═══ -->\n<g class=\"row-5 rule-card\">\n  <rect class=\"card-bg\" x=\"60\" y=\"417\" width=\"840\" height=\"68\" rx=\"12\" fill=\"#f5f3ff\"/>\n  <circle class=\"dot\" cx=\"88\" cy=\"451\" r=\"13\" fill=\"#d8b4fe\"><title>Constraint：設定品質限制條件</title></circle>\n  <text class=\"kw\" x=\"115\" y=\"446\" font-size=\"20\" font-weight=\"800\" fill=\"#7c3aed\">限制</text>\n  <text class=\"eng\" x=\"175\" y=\"446\" font-size=\"14\" font-weight=\"600\" fill=\"#a78bfa\">（Constraint）</text>\n  <text x=\"305\" y=\"446\" font-size=\"16\" fill=\"#94a3b8\">→</text>\n  <text class=\"example\" x=\"335\" y=\"446\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">「控制在 500 字內、語氣專業」</text>\n  <text class=\"example\" x=\"115\" y=\"470\" font-size=\"13\" font-weight=\"400\" fill=\"#94a3b8\">加上邊界條件讓產出更精確</text>\n  <g class=\"icon-box\" style=\"transform-origin:855px 451px;\"><text x=\"855\" y=\"459\" text-anchor=\"middle\" font-size=\"22\">⚙️</text></g>\n</g>\n\n<!-- 底部 -->\n<g class=\"footer\">\n  <line x1=\"200\" y1=\"505\" x2=\"760\" y2=\"505\" stroke=\"#e2e8f0\" stroke-width=\"1\"/>\n  <text x=\"480\" y=\"530\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">五要素齊全 = 一次到位的高品質 AI 產出</text>\n</g>\n</svg>\n"},{"name":"Vibe Coding 三大架構","description":"程式碼/伺服器/資料庫三角架構圖，含動態連線與hover互動","type":"svg","tags":["架構","Vibe Coding","教學"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes drawPath { from { stroke-dashoffset: 600; } to { stroke-dashoffset: 0; } }\n  @keyframes scaleIn { from { transform: scale(0); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n  @keyframes float { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-6px); } }\n  @keyframes pulse { 0%,100% { r: 5; opacity: 0.8; } 50% { r: 7; opacity: 1; } }\n\n  .title { animation: slideUp 0.6s ease-out both; }\n  .conn-line { stroke-dasharray: 600; animation: drawPath 1.2s ease-out 0.5s both; }\n  .node-code { animation: scaleIn 0.5s ease-out 0.6s both; transform-origin: 200px 300px; }\n  .node-server { animation: scaleIn 0.5s ease-out 0.8s both; transform-origin: 580px 140px; }\n  .node-db { animation: scaleIn 0.5s ease-out 1.0s both; transform-origin: 720px 370px; }\n  .label { animation: fadeIn 0.4s ease-out 1.2s both; }\n  .arrow-label { animation: fadeIn 0.4s ease-out 1.4s both; }\n  .footer { animation: fadeIn 0.4s ease-out 1.6s both; }\n\n  .node-group { cursor: pointer; }\n  .node-group:hover .node-bg { filter: drop-shadow(0 4px 16px rgba(0,0,0,0.2)) brightness(1.05); }\n  .node-group:hover .node-icon { animation: float 1.5s ease-in-out infinite; }\n  .node-bg { transition: filter 0.3s; }\n  .node-icon { transition: transform 0.2s; }\n\n  .conn-dot { animation: pulse 2s ease-in-out infinite; }\n  .conn-dot-1 { animation-delay: 0s; }\n  .conn-dot-2 { animation-delay: 0.7s; }\n  .conn-dot-3 { animation-delay: 1.4s; }\n</style>\n\n<!-- 背景 -->\n<rect width=\"960\" height=\"540\" fill=\"#ffffff\" rx=\"16\"/>\n\n<!-- 標題 -->\n<text class=\"title\" x=\"60\" y=\"60\" font-size=\"28\" font-weight=\"800\" fill=\"#1e293b\">Vibe Coding 必懂的三大架構</text>\n<text class=\"title\" x=\"900\" y=\"60\" text-anchor=\"end\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\" style=\"animation-delay:0.3s;\">前端 × 後端 × 資料庫</text>\n\n<!-- ═══ 連接線（三角形曲線）═══ -->\n<!-- 程式碼 → 伺服器 -->\n<path class=\"conn-line\" d=\"M 260 280 C 340 200, 440 140, 520 145\" fill=\"none\" stroke=\"#cbd5e1\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n<!-- 伺服器 → 資料庫 -->\n<path class=\"conn-line\" d=\"M 640 180 C 680 240, 720 290, 720 330\" fill=\"none\" stroke=\"#cbd5e1\" stroke-width=\"2.5\" stroke-linecap=\"round\" style=\"animation-delay:0.7s;\"/>\n<!-- 資料庫 → 程式碼 -->\n<path class=\"conn-line\" d=\"M 660 400 C 540 440, 360 420, 240 350\" fill=\"none\" stroke=\"#cbd5e1\" stroke-width=\"2.5\" stroke-linecap=\"round\" style=\"animation-delay:0.9s;\"/>\n\n<!-- 連接線上的動態圓點 -->\n<circle class=\"conn-dot conn-dot-1\" cx=\"390\" cy=\"195\" r=\"5\" fill=\"#6366f1\"/>\n<circle class=\"conn-dot conn-dot-2\" cx=\"690\" cy=\"255\" r=\"5\" fill=\"#6366f1\"/>\n<circle class=\"conn-dot conn-dot-3\" cx=\"440\" cy=\"415\" r=\"5\" fill=\"#6366f1\"/>\n\n<!-- 箭頭標籤 -->\n<g class=\"arrow-label\">\n  <rect x=\"330\" y=\"170\" width=\"100\" height=\"24\" rx=\"6\" fill=\"rgba(99,102,241,0.06)\"/>\n  <text x=\"380\" y=\"187\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#6366f1\">API 請求</text>\n</g>\n<g class=\"arrow-label\" style=\"animation-delay:1.5s;\">\n  <rect x=\"720\" y=\"248\" width=\"100\" height=\"24\" rx=\"6\" fill=\"rgba(99,102,241,0.06)\"/>\n  <text x=\"770\" y=\"265\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#6366f1\">讀寫資料</text>\n</g>\n<g class=\"arrow-label\" style=\"animation-delay:1.6s;\">\n  <rect x=\"390\" y=\"435\" width=\"100\" height=\"24\" rx=\"6\" fill=\"rgba(99,102,241,0.06)\"/>\n  <text x=\"440\" y=\"452\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#6366f1\">顯示結果</text>\n</g>\n\n<!-- ═══ Node 1: 程式碼 ═══ -->\n<g class=\"node-code node-group\">\n  <circle class=\"node-bg\" cx=\"200\" cy=\"300\" r=\"68\" fill=\"#f8fafc\" stroke=\"#e2e8f0\" stroke-width=\"2\"/>\n  <g class=\"node-icon\">\n    <!-- <> icon -->\n    <text x=\"200\" y=\"290\" text-anchor=\"middle\" font-size=\"42\" font-weight=\"900\" fill=\"#1e293b\" font-family=\"'SF Mono', Consolas, monospace\">&lt;/&gt;</text>\n  </g>\n  <text x=\"200\" y=\"335\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#94a3b8\">FRONTEND</text>\n  <title>前端程式碼：使用者看到的介面</title>\n</g>\n<g class=\"label\">\n  <text x=\"200\" y=\"400\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#1e293b\">程式碼</text>\n  <text x=\"200\" y=\"422\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"500\" fill=\"#64748b\">HTML / CSS / JS</text>\n</g>\n\n<!-- ═══ Node 2: 伺服器 ═══ -->\n<g class=\"node-server node-group\">\n  <circle class=\"node-bg\" cx=\"580\" cy=\"140\" r=\"68\" fill=\"#f8fafc\" stroke=\"#e2e8f0\" stroke-width=\"2\"/>\n  <g class=\"node-icon\">\n    <!-- Cloud icon -->\n    <path d=\"M 555 150 C 555 130, 570 118, 585 118 C 592 108, 606 108, 612 118 C 622 118, 632 128, 632 140 C 638 142, 640 150, 636 156 L 544 156 C 540 150, 542 142, 548 140 Z\" fill=\"#1e293b\"/>\n  </g>\n  <text x=\"580\" y=\"174\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#94a3b8\">BACKEND</text>\n  <title>後端伺服器：處理商業邏輯與 API</title>\n</g>\n<g class=\"label\" style=\"animation-delay:1.25s;\">\n  <text x=\"580\" y=\"240\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#1e293b\">伺服器</text>\n  <text x=\"580\" y=\"262\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"500\" fill=\"#64748b\">AWS / GCP / Vercel</text>\n</g>\n\n<!-- ═══ Node 3: 資料庫 ═══ -->\n<g class=\"node-db node-group\">\n  <circle class=\"node-bg\" cx=\"720\" cy=\"370\" r=\"68\" fill=\"#f8fafc\" stroke=\"#e2e8f0\" stroke-width=\"2\"/>\n  <g class=\"node-icon\">\n    <!-- Database icon -->\n    <ellipse cx=\"720\" cy=\"348\" rx=\"22\" ry=\"8\" fill=\"none\" stroke=\"#1e293b\" stroke-width=\"3\"/>\n    <path d=\"M 698 348 L 698 380 C 698 385, 708 390, 720 390 C 732 390, 742 385, 742 380 L 742 348\" fill=\"none\" stroke=\"#1e293b\" stroke-width=\"3\"/>\n    <path d=\"M 698 360 C 698 365, 708 370, 720 370 C 732 370, 742 365, 742 360\" fill=\"none\" stroke=\"#1e293b\" stroke-width=\"2.5\"/>\n  </g>\n  <text x=\"720\" y=\"404\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"600\" fill=\"#94a3b8\">DATABASE</text>\n  <title>資料庫：儲存與管理資料</title>\n</g>\n<g class=\"label\" style=\"animation-delay:1.3s;\">\n  <text x=\"720\" y=\"468\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#1e293b\">資料庫</text>\n  <text x=\"720\" y=\"490\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"500\" fill=\"#64748b\">PostgreSQL / SQL</text>\n</g>\n\n<!-- 底部 -->\n<g class=\"footer\">\n  <line x1=\"60\" y1=\"510\" x2=\"900\" y2=\"510\" stroke=\"#f1f5f9\" stroke-width=\"1\"/>\n  <text x=\"480\" y=\"530\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\">三者協作形成完整的 Web 應用程式架構</text>\n</g>\n</svg>\n"},{"name":"Lovable 三大觀念","description":"對話成本/真實數據/三合一架構，Vibe Coding 教學用","type":"svg","tags":["Lovable","Vibe Coding","觀念","教學"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes scaleIn { from { transform: scale(0); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n  @keyframes float { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-6px); } }\n\n  .title { animation: slideUp 0.6s ease-out both; }\n  .subtitle { animation: fadeIn 0.5s ease-out 0.3s both; }\n  .card-1 { animation: slideUp 0.5s ease-out 0.5s both; }\n  .card-2 { animation: slideUp 0.5s ease-out 0.7s both; }\n  .card-3 { animation: slideUp 0.5s ease-out 0.9s both; }\n  .num-badge { animation: scaleIn 0.4s ease-out both; }\n  .num-1 { animation-delay: 0.5s; transform-origin: 193px 148px; }\n  .num-2 { animation-delay: 0.7s; transform-origin: 480px 148px; }\n  .num-3 { animation-delay: 0.9s; transform-origin: 767px 148px; }\n  .footer { animation: fadeIn 0.4s ease-out 1.2s both; }\n\n  .concept-card { cursor: pointer; }\n  .concept-card .card-bg { transition: all 0.3s; }\n  .concept-card:hover .card-bg { fill: #f8fafc; filter: drop-shadow(0 8px 24px rgba(0,0,0,0.1)); transform: translateY(-4px); }\n  .concept-card:hover .icon-circle { fill: #1e293b; }\n  .concept-card:hover .icon-symbol { fill: #ffffff; }\n  .concept-card:hover .icon-stroke { stroke: #ffffff; }\n  .concept-card:hover .card-title { fill: #6366f1; }\n  .icon-circle { transition: fill 0.3s; }\n  .icon-symbol { transition: fill 0.3s; }\n  .icon-stroke { transition: stroke 0.3s; }\n  .card-title { transition: fill 0.2s; }\n  .concept-card:hover .float-icon { animation: float 1.5s ease-in-out infinite; }\n</style>\n\n<!-- 背景 -->\n<rect width=\"960\" height=\"540\" fill=\"#ffffff\" rx=\"16\"/>\n\n<!-- 頂部色帶 -->\n<rect x=\"0\" y=\"0\" width=\"960\" height=\"5\" rx=\"2.5\" fill=\"url(#topBar)\"/>\n<defs>\n  <linearGradient id=\"topBar\" x1=\"0\" y1=\"0\" x2=\"960\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#6366f1\"/>\n    <stop offset=\"50%\" stop-color=\"#8b5cf6\"/>\n    <stop offset=\"100%\" stop-color=\"#a855f7\"/>\n  </linearGradient>\n</defs>\n\n<!-- 標題 -->\n<text class=\"title\" x=\"480\" y=\"60\" text-anchor=\"middle\" font-size=\"30\" font-weight=\"800\" fill=\"#1e293b\">Vibe Coding 三個重要觀念</text>\n<text class=\"subtitle\" x=\"480\" y=\"88\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">使用 Lovable 開發前，你一定要知道的事</text>\n\n<!-- ═══ Card 1: 每次對話都要錢 ═══ -->\n<g class=\"card-1 concept-card\">\n  <rect class=\"card-bg\" x=\"50\" y=\"115\" width=\"260\" height=\"310\" rx=\"16\" fill=\"#ffffff\" stroke=\"#e2e8f0\" stroke-width=\"1.5\"/>\n  \n  <!-- 數字 badge -->\n  <circle class=\"num-badge num-1\" cx=\"193\" cy=\"148\" r=\"16\" fill=\"#6366f1\"/>\n  <text x=\"193\" y=\"154\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"800\" fill=\"#fff\">1</text>\n  \n  <!-- Icon -->\n  <g class=\"float-icon\">\n    <circle class=\"icon-circle\" cx=\"180\" cy=\"235\" r=\"46\" fill=\"#f1f5f9\"/>\n    <!-- $ symbol -->\n    <text class=\"icon-symbol\" x=\"180\" y=\"252\" text-anchor=\"middle\" font-size=\"44\" font-weight=\"800\" fill=\"#1e293b\" font-family=\"'SF Mono', Consolas, monospace\">$</text>\n  </g>\n  \n  <!-- 文字 -->\n  <text class=\"card-title\" x=\"180\" y=\"315\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#1e293b\">每次對話都要錢</text>\n  <text x=\"180\" y=\"345\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#64748b\">Lovable 按訊息數計費</text>\n  <text x=\"180\" y=\"367\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#64748b\">每一句 prompt 都是成本</text>\n  <text x=\"180\" y=\"395\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#a855f7\">💡 想清楚再送出</text>\n</g>\n\n<!-- ═══ Card 2: 提供真實數據 ═══ -->\n<g class=\"card-2 concept-card\">\n  <rect class=\"card-bg\" x=\"350\" y=\"115\" width=\"260\" height=\"310\" rx=\"16\" fill=\"#ffffff\" stroke=\"#e2e8f0\" stroke-width=\"1.5\"/>\n  \n  <circle class=\"num-badge num-2\" cx=\"480\" cy=\"148\" r=\"16\" fill=\"#8b5cf6\"/>\n  <text x=\"480\" y=\"154\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"800\" fill=\"#fff\">2</text>\n  \n  <g class=\"float-icon\">\n    <circle class=\"icon-circle\" cx=\"480\" cy=\"235\" r=\"46\" fill=\"#f1f5f9\"/>\n    <!-- Database icon -->\n    <ellipse class=\"icon-stroke\" cx=\"480\" cy=\"220\" rx=\"20\" ry=\"7\" fill=\"none\" stroke=\"#1e293b\" stroke-width=\"3\"/>\n    <path class=\"icon-stroke\" d=\"M 460 220 L 460 248 C 460 253, 469 258, 480 258 C 491 258, 500 253, 500 248 L 500 220\" fill=\"none\" stroke=\"#1e293b\" stroke-width=\"3\"/>\n    <path class=\"icon-stroke\" d=\"M 460 232 C 460 237, 469 242, 480 242 C 491 242, 500 237, 500 232\" fill=\"none\" stroke=\"#1e293b\" stroke-width=\"2.5\"/>\n  </g>\n  \n  <text class=\"card-title\" x=\"480\" y=\"315\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#1e293b\">用真實數據開發</text>\n  <text x=\"480\" y=\"345\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#64748b\">提供真實的內容與場景</text>\n  <text x=\"480\" y=\"367\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#64748b\">AI 才能做出實用成品</text>\n  <text x=\"480\" y=\"395\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#a855f7\">💡 別用假資料佔位</text>\n</g>\n\n<!-- ═══ Card 3: 三合一架構 ═══ -->\n<g class=\"card-3 concept-card\">\n  <rect class=\"card-bg\" x=\"650\" y=\"115\" width=\"260\" height=\"310\" rx=\"16\" fill=\"#ffffff\" stroke=\"#e2e8f0\" stroke-width=\"1.5\"/>\n  \n  <circle class=\"num-badge num-3\" cx=\"780\" cy=\"148\" r=\"16\" fill=\"#a855f7\"/>\n  <text x=\"780\" y=\"154\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"800\" fill=\"#fff\">3</text>\n  \n  <g class=\"float-icon\">\n    <circle class=\"icon-circle\" cx=\"780\" cy=\"235\" r=\"46\" fill=\"#f1f5f9\"/>\n    <!-- Cloud + code + db combined icon -->\n    <path class=\"icon-stroke\" d=\"M 762 232 C 762 220, 770 212, 780 212 C 785 205, 795 205, 800 212 C 806 212, 812 218, 812 226 C 816 228, 818 232, 816 236 L 756 236 C 754 232, 755 228, 758 226 Z\" fill=\"none\" stroke=\"#1e293b\" stroke-width=\"2.5\"/>\n    <!-- Bottom connectors -->\n    <line class=\"icon-stroke\" x1=\"768\" y1=\"236\" x2=\"768\" y2=\"250\" stroke=\"#1e293b\" stroke-width=\"2\"/>\n    <line class=\"icon-stroke\" x1=\"780\" y1=\"236\" x2=\"780\" y2=\"250\" stroke=\"#1e293b\" stroke-width=\"2\"/>\n    <line class=\"icon-stroke\" x1=\"792\" y1=\"236\" x2=\"792\" y2=\"250\" stroke=\"#1e293b\" stroke-width=\"2\"/>\n    <text class=\"icon-symbol\" x=\"768\" y=\"260\" font-size=\"9\" font-weight=\"700\" fill=\"#1e293b\" font-family=\"monospace\">&lt;/&gt;</text>\n    <text class=\"icon-symbol\" x=\"786\" y=\"260\" font-size=\"9\" font-weight=\"700\" fill=\"#1e293b\" font-family=\"monospace\">DB</text>\n  </g>\n  \n  <text class=\"card-title\" x=\"780\" y=\"315\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#1e293b\">三合一架構</text>\n  <text x=\"780\" y=\"345\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#64748b\">伺服器 / 資料庫 / 程式碼</text>\n  <text x=\"780\" y=\"367\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#64748b\">Lovable 一次幫你搞定</text>\n  <text x=\"780\" y=\"395\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"#a855f7\">💡 全端一站式部署</text>\n</g>\n\n<!-- 底部 -->\n<g class=\"footer\">\n  <rect x=\"200\" y=\"460\" width=\"560\" height=\"44\" rx=\"10\" fill=\"#f8fafc\" stroke=\"#e2e8f0\" stroke-width=\"1\"/>\n  <text x=\"480\" y=\"488\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#64748b\">掌握這三點，讓你的 Lovable 開發效率翻倍 🚀</text>\n</g>\n</svg>\n"},{"name":"Planning 模式觀念","description":"複雜任務先用Plan模式：描述需求→審核計畫→執行開發","type":"svg","tags":["Vibe Coding","Planning","觀念","教學"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes drawLine { from { stroke-dashoffset: 400; } to { stroke-dashoffset: 0; } }\n  @keyframes expandWidth { from { width: 0; } to { width: 100%; } }\n  @keyframes pulseGlow { 0%,100% { filter: drop-shadow(0 0 0 rgba(99,102,241,0)); } 50% { filter: drop-shadow(0 0 16px rgba(99,102,241,0.3)); } }\n  @keyframes stepIn { from { opacity: 0; transform: translateX(-15px) scale(0.95); } to { opacity: 1; transform: translateX(0) scale(1); } }\n\n  .context { animation: slideUp 0.5s ease-out 0.2s both; }\n  .accent-line { stroke-dasharray: 400; animation: drawLine 0.6s ease-out 0.3s both; }\n  .main-text { animation: slideUp 0.6s ease-out 0.5s both; }\n  .plan-badge { animation: slideUp 0.5s ease-out 0.7s both; }\n  .sub-text { animation: fadeIn 0.5s ease-out 0.9s both; }\n  .step-1 { animation: stepIn 0.5s ease-out 1.1s both; }\n  .step-2 { animation: stepIn 0.5s ease-out 1.3s both; }\n  .step-3 { animation: stepIn 0.5s ease-out 1.5s both; }\n  .footer { animation: fadeIn 0.5s ease-out 1.7s both; }\n\n  .plan-badge { cursor: pointer; }\n  .plan-badge:hover rect { fill: #4f46e5; }\n  .plan-badge:hover text { fill: #ffffff; }\n  .plan-badge rect { transition: fill 0.25s; }\n  .plan-badge text { transition: fill 0.25s; }\n\n  .step-card { cursor: pointer; }\n  .step-card .step-bg { transition: all 0.25s; }\n  .step-card:hover .step-bg { fill: #f8fafc; filter: drop-shadow(0 4px 12px rgba(0,0,0,0.08)); }\n  .step-card:hover .step-num { fill: #4f46e5; }\n  .step-card:hover .step-label { fill: #1e293b; }\n  .step-num { transition: fill 0.2s; }\n  .step-label { transition: fill 0.2s; }\n\n  .glow { animation: pulseGlow 3s ease-in-out infinite; }\n</style>\n\n<!-- 背景 -->\n<rect width=\"960\" height=\"540\" fill=\"#ffffff\" rx=\"16\"/>\n\n<!-- 左側藍色裝飾線 -->\n<line class=\"accent-line\" x1=\"72\" y1=\"70\" x2=\"72\" y2=\"165\" stroke=\"#4f46e5\" stroke-width=\"5\" stroke-linecap=\"round\"/>\n\n<!-- 情境文字 -->\n<text class=\"context\" x=\"90\" y=\"100\" font-size=\"24\" font-weight=\"700\" fill=\"#1e293b\">當你需要進行一個</text>\n<text class=\"context\" x=\"90\" y=\"140\" font-size=\"24\" font-weight=\"700\" fill=\"#1e293b\">「<tspan fill=\"#4f46e5\" font-weight=\"800\">比較複雜的任務</tspan>」時</text>\n\n<!-- 箭頭指示 -->\n<text class=\"main-text\" x=\"480\" y=\"210\" text-anchor=\"middle\" font-size=\"18\" fill=\"#94a3b8\" style=\"animation-delay:0.6s;\">↓</text>\n\n<!-- Plan/Planning 核心強調 -->\n<g class=\"plan-badge glow\">\n  <rect x=\"200\" y=\"230\" width=\"560\" height=\"80\" rx=\"16\" fill=\"#eef2ff\" stroke=\"#c7d2fe\" stroke-width=\"2\"/>\n  <text x=\"480\" y=\"265\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#6366f1\">先使用</text>\n  <text x=\"480\" y=\"295\" text-anchor=\"middle\" font-size=\"28\" font-weight=\"800\" fill=\"#4f46e5\">「Plan / Planning 模式」</text>\n</g>\n\n<!-- 副標 -->\n<text class=\"sub-text\" x=\"480\" y=\"345\" text-anchor=\"middle\" font-size=\"16\" font-weight=\"500\" fill=\"#64748b\">確認內容正確後，再按執行。</text>\n\n<!-- 三步驟流程 -->\n<g class=\"step-1 step-card\">\n  <rect class=\"step-bg\" x=\"100\" y=\"380\" width=\"230\" height=\"80\" rx=\"12\" fill=\"#ffffff\" stroke=\"#e2e8f0\" stroke-width=\"1.5\"/>\n  <circle class=\"step-num\" cx=\"140\" cy=\"420\" r=\"18\" fill=\"#6366f1\" opacity=\"0.1\"/>\n  <text class=\"step-num\" x=\"140\" y=\"426\" text-anchor=\"middle\" font-size=\"16\" font-weight=\"800\" fill=\"#6366f1\">1</text>\n  <text class=\"step-label\" x=\"230\" y=\"414\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"700\" fill=\"#334155\">描述需求</text>\n  <text x=\"230\" y=\"436\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"500\" fill=\"#94a3b8\">告訴 AI 你要什麼</text>\n</g>\n\n<text class=\"step-1\" x=\"345\" y=\"425\" font-size=\"18\" fill=\"#cbd5e1\" style=\"animation-delay:1.2s;\">→</text>\n\n<g class=\"step-2 step-card\">\n  <rect class=\"step-bg\" x=\"365\" y=\"380\" width=\"230\" height=\"80\" rx=\"12\" fill=\"#ffffff\" stroke=\"#e2e8f0\" stroke-width=\"1.5\"/>\n  <circle class=\"step-num\" cx=\"405\" cy=\"420\" r=\"18\" fill=\"#8b5cf6\" opacity=\"0.1\"/>\n  <text class=\"step-num\" x=\"405\" y=\"426\" text-anchor=\"middle\" font-size=\"16\" font-weight=\"800\" fill=\"#8b5cf6\">2</text>\n  <text class=\"step-label\" x=\"500\" y=\"414\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"700\" fill=\"#334155\">審核計畫</text>\n  <text x=\"500\" y=\"436\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"500\" fill=\"#94a3b8\">確認 AI 理解正確</text>\n</g>\n\n<text class=\"step-2\" x=\"610\" y=\"425\" font-size=\"18\" fill=\"#cbd5e1\" style=\"animation-delay:1.4s;\">→</text>\n\n<g class=\"step-3 step-card\">\n  <rect class=\"step-bg\" x=\"630\" y=\"380\" width=\"230\" height=\"80\" rx=\"12\" fill=\"#ffffff\" stroke=\"#e2e8f0\" stroke-width=\"1.5\"/>\n  <circle class=\"step-num\" cx=\"670\" cy=\"420\" r=\"18\" fill=\"#22c55e\" opacity=\"0.1\"/>\n  <text class=\"step-num\" x=\"670\" y=\"426\" text-anchor=\"middle\" font-size=\"16\" font-weight=\"800\" fill=\"#22c55e\">3</text>\n  <text class=\"step-label\" x=\"765\" y=\"414\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"700\" fill=\"#334155\">執行開發</text>\n  <text x=\"765\" y=\"436\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"500\" fill=\"#94a3b8\">按下 Execute 開始</text>\n</g>\n\n<!-- 底部 -->\n<g class=\"footer\">\n  <line x1=\"200\" y1=\"490\" x2=\"760\" y2=\"490\" stroke=\"#f1f5f9\" stroke-width=\"1\"/>\n  <text x=\"480\" y=\"518\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\">先規劃再執行 — 省下 80% 的來回修改時間 ⏱️</text>\n</g>\n</svg>\n"},{"name":"AI 簡報最佳工作流","description":"5步驟：AI大綱→AI初版→人工優化→設計加分→最終檢查","type":"svg","tags":["AI","簡報","工作流","教學"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes slideUp { from { opacity: 0; transform: translateY(18px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes slideRight { from { opacity: 0; transform: translateX(-20px); } to { opacity: 1; transform: translateX(0); } }\n  @keyframes drawLine { from { stroke-dashoffset: 200; } to { stroke-dashoffset: 0; } }\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes scaleIn { from { transform: scale(0); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n  @keyframes progressFill { from { width: 0; } to { width: 100%; } }\n\n  .title { animation: slideUp 0.6s ease-out both; }\n  .title-line { animation: drawLine 0.6s ease-out 0.3s both; stroke-dasharray: 200; }\n  .row-1 { animation: slideRight 0.45s ease-out 0.4s both; }\n  .row-2 { animation: slideRight 0.45s ease-out 0.55s both; }\n  .row-3 { animation: slideRight 0.45s ease-out 0.7s both; }\n  .row-4 { animation: slideRight 0.45s ease-out 0.85s both; }\n  .row-5 { animation: slideRight 0.45s ease-out 1.0s both; }\n  .footer { animation: fadeIn 0.4s ease-out 1.3s both; }\n\n  .step-card { cursor: pointer; }\n  .step-card .card-bg { transition: opacity 0.25s; opacity: 0; }\n  .step-card:hover .card-bg { opacity: 1; }\n  .step-card:hover .step-kw { fill: #0f4f2f; }\n  .step-card:hover .step-desc { fill: #1e293b; }\n  .step-card:hover .step-tool { opacity: 1; }\n  .step-kw { transition: fill 0.2s; }\n  .step-desc { transition: fill 0.2s; }\n  .step-tool { transition: opacity 0.2s; opacity: 0.6; }\n\n  .dot { cursor: pointer; transition: r 0.2s, filter 0.2s; }\n  .dot:hover { r: 20; filter: drop-shadow(0 0 10px rgba(22,163,74,0.45)); }\n\n  .num { animation: scaleIn 0.35s ease-out both; }\n  .num-1 { animation-delay: 0.4s; transform-origin: 98px 143px; }\n  .num-2 { animation-delay: 0.55s; transform-origin: 98px 218px; }\n  .num-3 { animation-delay: 0.7s; transform-origin: 98px 293px; }\n  .num-4 { animation-delay: 0.85s; transform-origin: 98px 368px; }\n  .num-5 { animation-delay: 1.0s; transform-origin: 98px 443px; }\n\n  /* 進度條動畫 */\n  .progress-track { animation: fadeIn 0.3s ease-out 1.2s both; }\n  .progress-fill { animation: progressFill 1s ease-out 1.3s both; }\n</style>\n\n<!-- 背景 -->\n<rect width=\"960\" height=\"540\" fill=\"#ffffff\" rx=\"16\"/>\n\n<!-- 頂部色帶 -->\n<rect x=\"0\" y=\"0\" width=\"960\" height=\"5\" rx=\"2.5\" fill=\"url(#topG)\"/>\n<defs>\n  <linearGradient id=\"topG\" x1=\"0\" y1=\"0\" x2=\"960\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#16a34a\"/>\n    <stop offset=\"50%\" stop-color=\"#22c55e\"/>\n    <stop offset=\"100%\" stop-color=\"#4ade80\"/>\n  </linearGradient>\n  <linearGradient id=\"progG\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#16a34a\"/>\n    <stop offset=\"100%\" stop-color=\"#4ade80\"/>\n  </linearGradient>\n</defs>\n\n<!-- 標題 -->\n<text class=\"title\" x=\"80\" y=\"68\" font-size=\"28\" font-weight=\"800\" fill=\"#1e293b\">AI 簡報的最佳工作流</text>\n<line class=\"title-line\" x1=\"80\" y1=\"82\" x2=\"300\" y2=\"82\" stroke=\"#16a34a\" stroke-width=\"4\" stroke-linecap=\"round\"/>\n<text class=\"title\" x=\"880\" y=\"68\" text-anchor=\"end\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\" style=\"animation-delay:0.3s;\">5 步驟高效產出專業簡報</text>\n\n<!-- ═══ Step 1 ═══ -->\n<g class=\"row-1 step-card\">\n  <rect class=\"card-bg\" x=\"65\" y=\"105\" width=\"830\" height=\"70\" rx=\"12\" fill=\"#f0fdf4\"/>\n  <circle class=\"dot num num-1\" cx=\"98\" cy=\"140\" r=\"16\" fill=\"#16a34a\"/>\n  <text x=\"98\" y=\"146\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"800\" fill=\"#fff\">1</text>\n  <text class=\"step-kw\" x=\"130\" y=\"135\" font-size=\"18\" font-weight=\"800\" fill=\"#16a34a\">AI 產大綱</text>\n  <text x=\"272\" y=\"135\" font-size=\"15\" fill=\"#94a3b8\">→</text>\n  <text class=\"step-desc\" x=\"300\" y=\"135\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">用 Claude / ChatGPT 整理簡報結構</text>\n  <text class=\"step-tool\" x=\"300\" y=\"158\" font-size=\"12\" font-weight=\"600\" fill=\"#94a3b8\">🛠️ Claude · ChatGPT · Gemini</text>\n  <rect class=\"step-tool\" x=\"790\" y=\"123\" width=\"72\" height=\"28\" rx=\"8\" fill=\"rgba(22,163,74,0.08)\"/>\n  <text class=\"step-tool\" x=\"826\" y=\"142\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"700\" fill=\"#16a34a\">結構化</text>\n</g>\n\n<!-- ═══ Step 2 ═══ -->\n<g class=\"row-2 step-card\">\n  <rect class=\"card-bg\" x=\"65\" y=\"180\" width=\"830\" height=\"70\" rx=\"12\" fill=\"#f0fdf4\"/>\n  <circle class=\"dot num num-2\" cx=\"98\" cy=\"215\" r=\"16\" fill=\"#22c55e\"/>\n  <text x=\"98\" y=\"221\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"800\" fill=\"#fff\">2</text>\n  <text class=\"step-kw\" x=\"130\" y=\"210\" font-size=\"18\" font-weight=\"800\" fill=\"#16a34a\">AI 生成初版</text>\n  <text x=\"302\" y=\"210\" font-size=\"15\" fill=\"#94a3b8\">→</text>\n  <text class=\"step-desc\" x=\"330\" y=\"210\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">用 Gamma 快速產出視覺化簡報</text>\n  <text class=\"step-tool\" x=\"330\" y=\"233\" font-size=\"12\" font-weight=\"600\" fill=\"#94a3b8\">🛠️ Gamma · Beautiful.ai · Tome</text>\n  <rect class=\"step-tool\" x=\"790\" y=\"198\" width=\"72\" height=\"28\" rx=\"8\" fill=\"rgba(22,163,74,0.08)\"/>\n  <text class=\"step-tool\" x=\"826\" y=\"217\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"700\" fill=\"#16a34a\">視覺化</text>\n</g>\n\n<!-- ═══ Step 3 ═══ -->\n<g class=\"row-3 step-card\">\n  <rect class=\"card-bg\" x=\"65\" y=\"255\" width=\"830\" height=\"70\" rx=\"12\" fill=\"#f0fdf4\"/>\n  <circle class=\"dot num num-3\" cx=\"98\" cy=\"290\" r=\"16\" fill=\"#4ade80\"/>\n  <text x=\"98\" y=\"296\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"800\" fill=\"#fff\">3</text>\n  <text class=\"step-kw\" x=\"130\" y=\"285\" font-size=\"18\" font-weight=\"800\" fill=\"#16a34a\">人工優化</text>\n  <text x=\"272\" y=\"285\" font-size=\"15\" fill=\"#94a3b8\">→</text>\n  <text class=\"step-desc\" x=\"300\" y=\"285\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">品牌色、公司 Logo、關鍵數據校正</text>\n  <text class=\"step-tool\" x=\"300\" y=\"308\" font-size=\"12\" font-weight=\"600\" fill=\"#94a3b8\">👤 人工介入確保品牌一致性</text>\n  <rect class=\"step-tool\" x=\"790\" y=\"273\" width=\"72\" height=\"28\" rx=\"8\" fill=\"rgba(234,179,8,0.08)\"/>\n  <text class=\"step-tool\" x=\"826\" y=\"292\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"700\" fill=\"#ca8a04\">品牌化</text>\n</g>\n\n<!-- ═══ Step 4 ═══ -->\n<g class=\"row-4 step-card\">\n  <rect class=\"card-bg\" x=\"65\" y=\"330\" width=\"830\" height=\"70\" rx=\"12\" fill=\"#f0fdf4\"/>\n  <circle class=\"dot num num-4\" cx=\"98\" cy=\"365\" r=\"16\" fill=\"#86efac\"/>\n  <text x=\"98\" y=\"371\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"800\" fill=\"#166534\">4</text>\n  <text class=\"step-kw\" x=\"130\" y=\"360\" font-size=\"18\" font-weight=\"800\" fill=\"#16a34a\">設計加分</text>\n  <text x=\"272\" y=\"360\" font-size=\"15\" fill=\"#94a3b8\">→</text>\n  <text class=\"step-desc\" x=\"300\" y=\"360\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">用更好的圖片模型產生高質感圖片</text>\n  <text class=\"step-tool\" x=\"300\" y=\"383\" font-size=\"12\" font-weight=\"600\" fill=\"#94a3b8\">🛠️ Midjourney · DALL-E · Ideogram</text>\n  <rect class=\"step-tool\" x=\"790\" y=\"348\" width=\"72\" height=\"28\" rx=\"8\" fill=\"rgba(22,163,74,0.08)\"/>\n  <text class=\"step-tool\" x=\"826\" y=\"367\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"700\" fill=\"#16a34a\">質感</text>\n</g>\n\n<!-- ═══ Step 5 ═══ -->\n<g class=\"row-5 step-card\">\n  <rect class=\"card-bg\" x=\"65\" y=\"405\" width=\"830\" height=\"70\" rx=\"12\" fill=\"#f0fdf4\"/>\n  <circle class=\"dot num num-5\" cx=\"98\" cy=\"440\" r=\"16\" fill=\"#bbf7d0\"/>\n  <text x=\"98\" y=\"446\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"800\" fill=\"#166534\">5</text>\n  <text class=\"step-kw\" x=\"130\" y=\"435\" font-size=\"18\" font-weight=\"800\" fill=\"#16a34a\">最終檢查</text>\n  <text x=\"290\" y=\"435\" font-size=\"15\" fill=\"#94a3b8\">→</text>\n  <text class=\"step-desc\" x=\"318\" y=\"435\" font-size=\"16\" font-weight=\"500\" fill=\"#475569\">AI 校稿 + 人工確認</text>\n  <text class=\"step-tool\" x=\"318\" y=\"458\" font-size=\"12\" font-weight=\"600\" fill=\"#94a3b8\">🛠️ AI 檢查錯字 · 人工最終審核</text>\n  <rect class=\"step-tool\" x=\"790\" y=\"423\" width=\"72\" height=\"28\" rx=\"8\" fill=\"rgba(99,102,241,0.08)\"/>\n  <text class=\"step-tool\" x=\"826\" y=\"442\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"700\" fill=\"#6366f1\">交付</text>\n</g>\n\n<!-- 底部進度條 -->\n<g class=\"footer\">\n  <rect class=\"progress-track\" x=\"80\" y=\"498\" width=\"800\" height=\"6\" rx=\"3\" fill=\"#f1f5f9\"/>\n  <rect class=\"progress-fill\" x=\"80\" y=\"498\" width=\"800\" height=\"6\" rx=\"3\" fill=\"url(#progG)\"/>\n  <text x=\"480\" y=\"528\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\">AI 輔助 × 人工把關 = 專業級簡報 🎯</text>\n</g>\n</svg>\n"},{"name":"AI 的產出等級","description":"四等級矩陣：對話式文字→對話式圖片影音→線上靜態服務→客製化系統，含hover互動與進場動畫","type":"svg","tags":["AI","產出","等級","教學"],"content":"<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 960 540\" font-family=\"'Noto Sans TC', sans-serif\">\n<style>\n  @keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }\n  @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n  @keyframes scaleIn { from { transform: scale(0.85); opacity: 0; } to { transform: scale(1); opacity: 1; } }\n  @keyframes drawLine { from { stroke-dashoffset: 800; } to { stroke-dashoffset: 0; } }\n  @keyframes shimmer { 0% { opacity: 0.4; } 50% { opacity: 0.8; } 100% { opacity: 0.4; } }\n\n  .title { animation: slideUp 0.6s ease-out both; }\n  .subtitle { animation: fadeIn 0.5s ease-out 0.3s both; }\n  .col-1 { animation: scaleIn 0.5s ease-out 0.5s both; transform-origin: 160px 290px; }\n  .col-2 { animation: scaleIn 0.5s ease-out 0.7s both; transform-origin: 380px 290px; }\n  .col-3 { animation: scaleIn 0.5s ease-out 0.9s both; transform-origin: 600px 290px; }\n  .col-4 { animation: scaleIn 0.5s ease-out 1.1s both; transform-origin: 820px 290px; }\n  .progress-bar { stroke-dasharray: 800; animation: drawLine 1.2s ease-out 1.3s both; }\n  .footer { animation: fadeIn 0.4s ease-out 1.5s both; }\n  .arrow-hint { animation: shimmer 2.5s ease-in-out 1.5s infinite; }\n\n  .level-card { cursor: pointer; }\n  .level-card .card-bg { transition: all 0.3s; }\n  .level-card:hover .card-bg { filter: drop-shadow(0 6px 20px rgba(0,0,0,0.12)); transform: translateY(-4px); }\n  .level-card:hover .card-title { fill: #ffffff; }\n  .level-card:hover .card-icon-bg { opacity: 0.25; }\n  .level-card:hover .example-text { fill: #f1f5f9; }\n  .card-title { transition: fill 0.2s; }\n  .card-icon-bg { transition: opacity 0.2s; opacity: 0.15; }\n  .example-text { transition: fill 0.2s; }\n\n  .level-num { transition: transform 0.2s; }\n  .level-card:hover .level-num { transform: scale(1.15); }\n</style>\n\n<!-- 背景 -->\n<rect width=\"960\" height=\"540\" fill=\"#ffffff\" rx=\"16\"/>\n\n<!-- 頂部漸層色帶 -->\n<rect x=\"0\" y=\"0\" width=\"960\" height=\"5\" rx=\"2.5\" fill=\"url(#lvlTopGrad)\"/>\n<defs>\n  <linearGradient id=\"lvlTopGrad\" x1=\"0\" y1=\"0\" x2=\"960\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#6366f1\"/>\n    <stop offset=\"33%\" stop-color=\"#a855f7\"/>\n    <stop offset=\"66%\" stop-color=\"#06b6d4\"/>\n    <stop offset=\"100%\" stop-color=\"#f59e0b\"/>\n  </linearGradient>\n  <linearGradient id=\"lvlCard1\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n    <stop offset=\"0%\" stop-color=\"#6366f1\"/>\n    <stop offset=\"100%\" stop-color=\"#4f46e5\"/>\n  </linearGradient>\n  <linearGradient id=\"lvlCard2\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n    <stop offset=\"0%\" stop-color=\"#a855f7\"/>\n    <stop offset=\"100%\" stop-color=\"#9333ea\"/>\n  </linearGradient>\n  <linearGradient id=\"lvlCard3\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n    <stop offset=\"0%\" stop-color=\"#06b6d4\"/>\n    <stop offset=\"100%\" stop-color=\"#0891b2\"/>\n  </linearGradient>\n  <linearGradient id=\"lvlCard4\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n    <stop offset=\"0%\" stop-color=\"#f59e0b\"/>\n    <stop offset=\"100%\" stop-color=\"#d97706\"/>\n  </linearGradient>\n  <linearGradient id=\"lvlBottomGrad\" x1=\"0\" y1=\"0\" x2=\"960\" y2=\"0\">\n    <stop offset=\"0%\" stop-color=\"#6366f1\"/>\n    <stop offset=\"33%\" stop-color=\"#a855f7\"/>\n    <stop offset=\"66%\" stop-color=\"#06b6d4\"/>\n    <stop offset=\"100%\" stop-color=\"#f59e0b\"/>\n  </linearGradient>\n</defs>\n\n<!-- 標題 -->\n<text class=\"title\" x=\"480\" y=\"55\" text-anchor=\"middle\" font-size=\"30\" font-weight=\"800\" fill=\"#1e293b\">AI 的產出等級</text>\n<text class=\"subtitle\" x=\"480\" y=\"82\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#94a3b8\">從對話產出到客製化系統 — 複雜度與價值遞增 →</text>\n\n<!-- ═══ Level 1: 對話式文字 ═══ -->\n<g class=\"col-1 level-card\">\n  <rect class=\"card-bg\" x=\"40\" y=\"110\" width=\"205\" height=\"340\" rx=\"16\" fill=\"url(#lvlCard1)\"/>\n  <!-- 等級數字 -->\n  <g class=\"level-num\" style=\"transform-origin:142px 148px;\">\n    <circle cx=\"142\" cy=\"148\" r=\"20\" fill=\"rgba(255,255,255,0.15)\"/>\n    <text x=\"142\" y=\"155\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"800\" fill=\"#ffffff\">Lv.1</text>\n  </g>\n  <!-- 圖示背景 -->\n  <circle class=\"card-icon-bg\" cx=\"142\" cy=\"215\" r=\"36\" fill=\"#ffffff\"/>\n  <!-- 文字對話 icon -->\n  <rect x=\"122\" y=\"198\" width=\"40\" height=\"30\" rx=\"6\" fill=\"none\" stroke=\"#ffffff\" stroke-width=\"2.5\"/>\n  <line x1=\"130\" y1=\"208\" x2=\"154\" y2=\"208\" stroke=\"#ffffff\" stroke-width=\"2\" stroke-linecap=\"round\"/>\n  <line x1=\"130\" y1=\"215\" x2=\"148\" y2=\"215\" stroke=\"#ffffff\" stroke-width=\"2\" stroke-linecap=\"round\"/>\n  <polygon points=\"132,228 140,228 134,236\" fill=\"#ffffff\"/>\n  <!-- 類型標題 -->\n  <text class=\"card-title\" x=\"142\" y=\"275\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#e0e7ff\">對話式文字</text>\n  <!-- 分隔線 -->\n  <line x1=\"70\" y1=\"292\" x2=\"215\" y2=\"292\" stroke=\"rgba(255,255,255,0.2)\" stroke-width=\"1\"/>\n  <!-- 應用範例 -->\n  <text x=\"142\" y=\"318\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"rgba(255,255,255,0.5)\" letter-spacing=\"2\">應用範例</text>\n  <text class=\"example-text\" x=\"142\" y=\"348\" text-anchor=\"middle\" font-size=\"17\" font-weight=\"600\" fill=\"#c7d2fe\">企劃、想法</text>\n  <text class=\"example-text\" x=\"142\" y=\"375\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#a5b4fc\">文案撰寫</text>\n  <text class=\"example-text\" x=\"142\" y=\"398\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#a5b4fc\">摘要整理</text>\n  <text class=\"example-text\" x=\"142\" y=\"421\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#a5b4fc\">翻譯改寫</text>\n  <title>Lv.1 對話式文字：最基礎的 AI 產出，如企劃撰寫、文案、摘要等</title>\n</g>\n\n<!-- ═══ Level 2: 對話式圖片、影音 ═══ -->\n<g class=\"col-2 level-card\">\n  <rect class=\"card-bg\" x=\"265\" y=\"110\" width=\"205\" height=\"340\" rx=\"16\" fill=\"url(#lvlCard2)\"/>\n  <g class=\"level-num\" style=\"transform-origin:367px 148px;\">\n    <circle cx=\"367\" cy=\"148\" r=\"20\" fill=\"rgba(255,255,255,0.15)\"/>\n    <text x=\"367\" y=\"155\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"800\" fill=\"#ffffff\">Lv.2</text>\n  </g>\n  <circle class=\"card-icon-bg\" cx=\"367\" cy=\"215\" r=\"36\" fill=\"#ffffff\"/>\n  <!-- 圖片 icon -->\n  <rect x=\"347\" y=\"200\" width=\"40\" height=\"30\" rx=\"5\" fill=\"none\" stroke=\"#ffffff\" stroke-width=\"2.5\"/>\n  <circle cx=\"357\" cy=\"210\" r=\"4\" fill=\"#ffffff\"/>\n  <polyline points=\"350,225 362,214 372,222 380,216 387,225\" fill=\"none\" stroke=\"#ffffff\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/>\n  <text class=\"card-title\" x=\"367\" y=\"275\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"700\" fill=\"#f3e8ff\">對話式圖片、影音</text>\n  <line x1=\"295\" y1=\"292\" x2=\"440\" y2=\"292\" stroke=\"rgba(255,255,255,0.2)\" stroke-width=\"1\"/>\n  <text x=\"367\" y=\"318\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"rgba(255,255,255,0.5)\" letter-spacing=\"2\">應用範例</text>\n  <text class=\"example-text\" x=\"367\" y=\"348\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"600\" fill=\"#e9d5ff\">廣告素材</text>\n  <text class=\"example-text\" x=\"367\" y=\"375\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"600\" fill=\"#e9d5ff\">菜單設計</text>\n  <text class=\"example-text\" x=\"367\" y=\"398\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"600\" fill=\"#e9d5ff\">母親節上菜</text>\n  <text class=\"example-text\" x=\"367\" y=\"421\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#d8b4fe\">影片腳本</text>\n  <title>Lv.2 對話式圖片、影音：AI 產生視覺素材，如廣告、菜單、行銷圖</title>\n</g>\n\n<!-- ═══ Level 3: 線上靜態服務 ═══ -->\n<g class=\"col-3 level-card\">\n  <rect class=\"card-bg\" x=\"490\" y=\"110\" width=\"205\" height=\"340\" rx=\"16\" fill=\"url(#lvlCard3)\"/>\n  <g class=\"level-num\" style=\"transform-origin:592px 148px;\">\n    <circle cx=\"592\" cy=\"148\" r=\"20\" fill=\"rgba(255,255,255,0.15)\"/>\n    <text x=\"592\" y=\"155\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"800\" fill=\"#ffffff\">Lv.3</text>\n  </g>\n  <circle class=\"card-icon-bg\" cx=\"592\" cy=\"215\" r=\"36\" fill=\"#ffffff\"/>\n  <!-- 瀏覽器 icon -->\n  <rect x=\"572\" y=\"198\" width=\"40\" height=\"32\" rx=\"5\" fill=\"none\" stroke=\"#ffffff\" stroke-width=\"2.5\"/>\n  <line x1=\"572\" y1=\"208\" x2=\"612\" y2=\"208\" stroke=\"#ffffff\" stroke-width=\"2\"/>\n  <circle cx=\"578\" cy=\"203\" r=\"2\" fill=\"#ffffff\"/>\n  <circle cx=\"584\" cy=\"203\" r=\"2\" fill=\"#ffffff\"/>\n  <circle cx=\"590\" cy=\"203\" r=\"2\" fill=\"#ffffff\"/>\n  <text class=\"card-title\" x=\"592\" y=\"275\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#e0f2fe\">線上靜態服務</text>\n  <line x1=\"520\" y1=\"292\" x2=\"665\" y2=\"292\" stroke=\"rgba(255,255,255,0.2)\" stroke-width=\"1\"/>\n  <text x=\"592\" y=\"318\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"rgba(255,255,255,0.5)\" letter-spacing=\"2\">應用範例</text>\n  <text class=\"example-text\" x=\"592\" y=\"348\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"600\" fill=\"#cffafe\">線上菜單</text>\n  <text class=\"example-text\" x=\"592\" y=\"375\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"600\" fill=\"#cffafe\">問卷表單</text>\n  <text class=\"example-text\" x=\"592\" y=\"398\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#a5f3fc\">Landing Page</text>\n  <text class=\"example-text\" x=\"592\" y=\"421\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#a5f3fc\">作品集網站</text>\n  <title>Lv.3 線上靜態服務：可獨立運作的網頁應用，如問卷、菜單頁面</title>\n</g>\n\n<!-- ═══ Level 4: 客製化系統 ═══ -->\n<g class=\"col-4 level-card\">\n  <rect class=\"card-bg\" x=\"715\" y=\"110\" width=\"205\" height=\"340\" rx=\"16\" fill=\"url(#lvlCard4)\"/>\n  <g class=\"level-num\" style=\"transform-origin:817px 148px;\">\n    <circle cx=\"817\" cy=\"148\" r=\"20\" fill=\"rgba(255,255,255,0.15)\"/>\n    <text x=\"817\" y=\"155\" text-anchor=\"middle\" font-size=\"18\" font-weight=\"800\" fill=\"#ffffff\">Lv.4</text>\n  </g>\n  <circle class=\"card-icon-bg\" cx=\"817\" cy=\"215\" r=\"36\" fill=\"#ffffff\"/>\n  <!-- 齒輪+資料庫 icon -->\n  <circle cx=\"810\" cy=\"212\" r=\"12\" fill=\"none\" stroke=\"#ffffff\" stroke-width=\"2.5\"/>\n  <circle cx=\"810\" cy=\"212\" r=\"4\" fill=\"#ffffff\"/>\n  <line x1=\"810\" y1=\"197\" x2=\"810\" y2=\"201\" stroke=\"#ffffff\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n  <line x1=\"810\" y1=\"223\" x2=\"810\" y2=\"227\" stroke=\"#ffffff\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n  <line x1=\"797\" y1=\"205\" x2=\"800\" y2=\"207\" stroke=\"#ffffff\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n  <line x1=\"820\" y1=\"217\" x2=\"823\" y2=\"219\" stroke=\"#ffffff\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n  <line x1=\"797\" y1=\"219\" x2=\"800\" y2=\"217\" stroke=\"#ffffff\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n  <line x1=\"820\" y1=\"207\" x2=\"823\" y2=\"205\" stroke=\"#ffffff\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n  <text class=\"card-title\" x=\"817\" y=\"275\" text-anchor=\"middle\" font-size=\"20\" font-weight=\"700\" fill=\"#fef3c7\">客製化系統</text>\n  <line x1=\"745\" y1=\"292\" x2=\"890\" y2=\"292\" stroke=\"rgba(255,255,255,0.2)\" stroke-width=\"1\"/>\n  <text x=\"817\" y=\"318\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"600\" fill=\"rgba(255,255,255,0.5)\" letter-spacing=\"2\">應用範例</text>\n  <text class=\"example-text\" x=\"817\" y=\"348\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#fef9c3\">排班表</text>\n  <text class=\"example-text\" x=\"817\" y=\"371\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#fef9c3\">競品監測系統</text>\n  <text class=\"example-text\" x=\"817\" y=\"394\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"600\" fill=\"#fef9c3\">客戶分群推播</text>\n  <text class=\"example-text\" x=\"817\" y=\"417\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"500\" fill=\"#fde68a\">CRM 整合</text>\n  <title>Lv.4 客製化系統：需要資料庫與後端的完整系統，如排班、CRM</title>\n</g>\n\n<!-- 底部漸層進度條 -->\n<g class=\"footer\">\n  <rect x=\"40\" y=\"472\" width=\"880\" height=\"6\" rx=\"3\" fill=\"#f1f5f9\"/>\n  <line class=\"progress-bar\" x1=\"40\" y1=\"475\" x2=\"920\" y2=\"475\" stroke=\"url(#lvlBottomGrad)\" stroke-width=\"6\" stroke-linecap=\"round\"/>\n  <!-- 箭頭提示 -->\n  <text class=\"arrow-hint\" x=\"480\" y=\"500\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"600\" fill=\"#94a3b8\">簡單 ─────────────────────────────────── 複雜</text>\n  <text x=\"480\" y=\"525\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"500\" fill=\"#94a3b8\">等級越高，AI 需要的架構與整合能力越強</text>\n</g>\n</svg>\n"}];